import React, { useState } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SearchSelect } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Building2, GitFork } from 'lucide-react';
import { MOCK_DOMAINS, BUSINESS_TYPES } from '../constants';
import { Domain } from '../types';

// Mock Customer Data for Selection
const MOCK_CUSTOMERS = [
  { id: 'c1', name: '安徽省电力公司', code: 'AH_POWER' },
  { id: 'c2', name: '江淮汽车集团', code: 'JAC_MOTORS' },
  { id: 'c3', name: '科大讯飞股份有限公司', code: 'IFLYTEK' },
  { id: 'c4', name: '合肥百货大楼集团', code: 'HF_DEPT' },
  { id: 'c5', name: '安徽海螺水泥', code: 'CONCH_CEMENT' },
  { id: 'c6', name: '铜陵有色金属', code: 'TNMG' },
  { id: 'c7', name: '阳光电源股份有限公司', code: 'SUNGROW' },
  { id: 'c8', name: '蔚来汽车（安徽）', code: 'NIO_AH' },
  { id: 'c9', name: '京东方科技集团', code: 'BOE_TECH' },
  { id: 'c10', name: '长鑫存储技术', code: 'CXMT' },
  { id: 'c11', name: '国元证券', code: 'GUOYUAN' },
  { id: 'c12', name: '华安证券', code: 'HUAAN' },
];

export const DomainManager: React.FC = () => {
  const [data, setData] = useState<Domain[]>(MOCK_DOMAINS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentDomain, setCurrentDomain] = useState<Partial<Domain> | null>(null);
  const [creationType, setCreationType] = useState<'company' | 'department'>('department');

  // Status Confirm State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);

  // Helper to flatten tree for table display and parent selection
  const flattenDomains = (domains: Domain[], depth = 0): (Domain & { depth: number })[] => {
    let result: (Domain & { depth: number })[] = [];
    domains.forEach(d => {
      result.push({ ...d, depth });
      if (d.children) {
        result = result.concat(flattenDomains(d.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = flattenDomains(data);

  const handleEdit = (domain: Domain) => {
    setCurrentDomain(domain);
    setCreationType(domain.parentId ? 'department' : 'company');
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    const defaultType = data.length > 0 ? 'department' : 'company';
    setCreationType(defaultType);
    setCurrentDomain({ 
      status: 'active', 
      businessTypes: [], 
      parentId: defaultType === 'department' ? (flatData[0]?.id || '') : null 
    });
    setIsModalOpen(true);
  };

  const handleTypeChange = (type: 'company' | 'department') => {
    setCreationType(type);
    if (type === 'company') {
      setCurrentDomain(prev => ({ ...prev, parentId: null, name: '', code: '' }));
    } else {
      setCurrentDomain(prev => ({ ...prev, parentId: flatData[0]?.id || '', name: '', code: '' }));
    }
  };

  const initiateStatusChange = (domain: Domain, checked: boolean) => {
     setTargetStatusChange({
         id: domain.id,
         newStatus: checked ? 'active' : 'inactive'
     });
     setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          // Recursive update helper
          const updateStatus = (items: Domain[]): Domain[] => {
              return items.map(item => {
                  if (item.id === targetStatusChange.id) {
                      return { ...item, status: targetStatusChange.newStatus };
                  }
                  if (item.children) {
                      return { ...item, children: updateStatus(item.children) };
                  }
                  return item;
              });
          };
          setData(updateStatus(data));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const columns = [
    { 
      header: '组织名称', 
      accessor: (row: any) => (
        <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center">
           {row.depth === 0 ? <Building2 size={16} className="text-blue-400 mr-2"/> : <GitFork size={16} className="text-slate-500 mr-2"/>}
           <span className={`font-medium ${row.depth === 0 ? 'text-blue-100' : 'text-slate-300'}`}>{row.name}</span>
           {row.depth === 0 && <Badge color="blue" className="ml-2 scale-90">公司</Badge>}
        </div>
      ) 
    },
    { header: '域编码', accessor: 'code' },
    { header: '管理员', accessor: 'manager' },
    { 
      header: '开通业务', 
      accessor: (row: Domain) => (
        <div className="flex gap-1 flex-wrap">
          {row.businessTypes.map(bt => {
             const label = BUSINESS_TYPES.find(b => b.code === bt)?.name || bt;
             return <Badge key={bt} color="gray">{label}</Badge>;
          })}
        </div>
      ) 
    },
    { 
      header: '状态', 
      accessor: (row: Domain) => (
        <Switch 
            checked={row.status === 'active'} 
            onChange={(checked) => initiateStatusChange(row, checked)} 
        />
      ) 
    },
    { header: '创建时间', accessor: 'createTime' },
    {
      header: '操作',
      accessor: (row: Domain) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />}>删除</Button>
        </div>
      )
    }
  ];

  const parentOptions = flatData
    .filter(d => d.id !== currentDomain?.id)
    .map(d => ({
      label: '　'.repeat(d.depth) + d.name,
      value: d.id
    }));

  const customerOptions = MOCK_CUSTOMERS.map(c => ({
      label: c.name,
      value: c.id,
      extra: c
  }));

  return (
    <div className="space-y-4 h-full flex flex-col">
      <Card className="shrink-0">
        <div className="flex flex-wrap gap-4 items-end">
           <Input label="域名称" placeholder="输入名称" className="w-48" />
           <Input label="域编码" placeholder="输入编码" className="w-48" />
           <Select label="状态" options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '禁用', value: 'inactive'}]} className="w-32" />
           <div className="flex gap-2 pb-0.5">
             <Button icon={<Search size={16} />}>查询</Button>
             <Button variant="secondary" icon={<RotateCcw size={16} />}>重置</Button>
             <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16} />} onClick={handleAdd}>新增组织</Button>
           </div>
        </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col" title="组织架构列表">
         <div className="flex-1 overflow-auto">
            <Table columns={columns} data={flatData} />
         </div>
         <div className="py-2 border-t border-slate-700 flex justify-end text-sm text-slate-400">
            共 {flatData.length} 条
         </div>
      </Card>

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={currentDomain?.id ? "编辑组织信息" : "新增组织"}
        footer={
          <>
            <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
            <Button onClick={() => setIsModalOpen(false)}>确定</Button>
          </>
        }
      >
        <div className="space-y-4">
           <div className="bg-slate-900/50 p-3 rounded border border-slate-700">
             <label className="text-sm font-medium text-slate-300 mb-2 block">节点类型</label>
             <div className="flex space-x-6">
                <label className={`flex items-center space-x-2 cursor-pointer ${currentDomain?.id ? 'opacity-50 cursor-not-allowed' : ''}`}>
                    <input 
                        type="radio" 
                        name="nodeType" 
                        checked={creationType === 'company'} 
                        onChange={() => !currentDomain?.id && handleTypeChange('company')}
                        disabled={!!currentDomain?.id}
                        className="text-blue-500 bg-slate-900 border-slate-600 focus:ring-blue-500" 
                    />
                    <span className={creationType === 'company' ? 'text-white font-medium' : 'text-slate-400'}>
                        一级公司 (租户)
                    </span>
                </label>
                <label className={`flex items-center space-x-2 cursor-pointer ${currentDomain?.id ? 'opacity-50 cursor-not-allowed' : ''}`}>
                    <input 
                        type="radio" 
                        name="nodeType" 
                        checked={creationType === 'department'} 
                        onChange={() => !currentDomain?.id && handleTypeChange('department')}
                        disabled={!!currentDomain?.id}
                        className="text-blue-500 bg-slate-900 border-slate-600 focus:ring-blue-500" 
                    />
                    <span className={creationType === 'department' ? 'text-white font-medium' : 'text-slate-400'}>
                        下级部门/分公司
                    </span>
                </label>
             </div>
           </div>

           {creationType === 'department' && (
               <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                   <Select 
                     label="归属上级 (公司/部门)" 
                     options={parentOptions} 
                     value={currentDomain?.parentId || ''}
                     onChange={(e) => setCurrentDomain(prev => ({ ...prev, parentId: e.target.value }))}
                   />
               </div>
           )}

           {creationType === 'company' && !currentDomain?.id ? (
                // Use SearchSelect for new Companies
                <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                    <SearchSelect
                        label="组织名称 (客户选择)"
                        options={customerOptions}
                        value={MOCK_CUSTOMERS.find(c => c.name === currentDomain?.name)?.id}
                        onChange={(val, opt) => {
                            if (opt) {
                                setCurrentDomain(prev => ({ ...prev, name: opt.label, code: opt.extra.code }));
                            } else {
                                // Allow custom input or clearing
                                setCurrentDomain(prev => ({ ...prev, name: val, code: '' })); 
                            }
                        }}
                        placeholder="请输入或选择客户名称..."
                    />
                </div>
           ) : (
                <Input label="组织名称" defaultValue={currentDomain?.name} placeholder="请输入部门名称" />
           )}

           <Input 
                label="组织编码" 
                value={currentDomain?.code || ''} 
                onChange={(e) => setCurrentDomain(prev => ({ ...prev, code: e.target.value }))}
                placeholder="唯一标识 (Code)" 
                disabled={!!currentDomain?.id || creationType === 'company'} // Auto-filled for companies or disabled on edit
           />

           <Input label="管理员账号" defaultValue={currentDomain?.manager} placeholder="关联初始管理员" />

           <div>
             <label className="text-sm font-medium text-slate-300 mb-2 block">开通业务类型</label>
             <div className="grid grid-cols-2 gap-2">
               {BUSINESS_TYPES.map(bt => (
                 <label key={bt.code} className="flex items-center space-x-2 p-2 rounded border border-slate-700 hover:bg-slate-800 cursor-pointer">
                   <input type="checkbox" className="rounded border-slate-600 bg-slate-900 text-blue-600" defaultChecked={currentDomain?.businessTypes?.includes(bt.code)} />
                   <span className="text-sm">{bt.name}</span>
                 </label>
               ))}
             </div>
           </div>

           <Input label="备注" />
        </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '禁用'}该组织吗？此操作可能会影响该组织下所有用户的访问权限。`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />
    </div>
  );
};

import React, { useState } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Folder, FileText, MousePointer, Search } from 'lucide-react';
import { MOCK_MENUS } from '../constants';
import { Menu } from '../types';

export const MenuManager: React.FC = () => {
  const [data, setData] = useState<Menu[]>(MOCK_MENUS);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newVisible: boolean } | null>(null);

  const flattenMenus = (menus: Menu[], depth = 0): (Menu & { depth: number })[] => {
    let result: (Menu & { depth: number })[] = [];
    menus.forEach(m => {
      result.push({ ...m, depth });
      if (m.children) {
        result = result.concat(flattenMenus(m.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = flattenMenus(data);

  const initiateStatusChange = (menu: Menu, checked: boolean) => {
    setTargetStatusChange({ id: menu.id, newVisible: checked });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
     if (targetStatusChange) {
         const updateVisible = (items: Menu[]): Menu[] => {
             return items.map(item => {
                 if (item.id === targetStatusChange.id) {
                     return { ...item, visible: targetStatusChange.newVisible };
                 }
                 if (item.children) {
                     return { ...item, children: updateVisible(item.children) };
                 }
                 return item;
             });
         };
         setData(updateVisible(data));
     }
     setConfirmOpen(false);
     setTargetStatusChange(null);
  };

  const columns = [
    { 
      header: '菜单名称', 
      accessor: (row: any) => (
        <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center">
           {row.type === 'dir' && <Folder size={16} className="text-yellow-500 mr-2" />}
           {row.type === 'menu' && <FileText size={16} className="text-blue-400 mr-2" />}
           {row.type === 'button' && <MousePointer size={16} className="text-slate-400 mr-2" />}
           <span className="text-slate-200">{row.name}</span>
        </div>
      ) 
    },
    { header: '路由地址', accessor: (row: Menu) => <span className="text-slate-400 font-mono text-xs">{row.path || '-'}</span> },
    { header: '权限标识', accessor: (row: Menu) => <Badge color="gray">{row.permission || '-'}</Badge> },
    { header: '组件路径', accessor: (row: Menu) => <span className="text-slate-500 text-xs">{row.component || '-'}</span> },
    { header: '排序', accessor: 'sort', width: '80px' },
    { 
      header: '状态', 
      accessor: (row: Menu) => (
        <Switch 
          checked={row.visible} 
          onChange={(checked) => initiateStatusChange(row, checked)} 
        />
      ) 
    },
    {
      header: '操作',
      accessor: (row: Menu) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />}>删除</Button>
        </div>
      )
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
      <Card className="shrink-0">
         <div className="flex justify-between items-center">
            <div className="flex gap-2">
                <Input placeholder="菜单名称" className="w-64" />
                <Button icon={<Search size={16} />}>查询</Button>
            </div>
            <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16} />} onClick={() => setIsModalOpen(true)}>新增菜单</Button>
         </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-auto">
          <Table columns={columns} data={flatData} />
        </div>
      </Card>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title="新增菜单"
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={() => setIsModalOpen(false)}>确定</Button>
            </>
          }
      >
         <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                    <label className="text-sm font-medium text-slate-300 mb-2 block">类型</label>
                    <div className="flex space-x-4">
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input type="radio" name="type" className="text-blue-500 bg-slate-900 border-slate-600" defaultChecked />
                            <span>目录</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input type="radio" name="type" className="text-blue-500 bg-slate-900 border-slate-600" />
                            <span>菜单</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input type="radio" name="type" className="text-blue-500 bg-slate-900 border-slate-600" />
                            <span>按钮</span>
                        </label>
                    </div>
                </div>

                <Select label="上级菜单" options={[{label: '主目录', value: '0'}, {label: '系统管理', value: '1'}]} />
                <Input label="菜单名称" placeholder="请输入名称" />

                <Input label="路由地址" placeholder="/system/..." />
                <Input label="组件路径" placeholder="views/system/..." />

                <Input label="权限标识" placeholder="sys:user:add" className="col-span-2" />

                <div className="col-span-2 flex space-x-6">
                     <div className="flex items-center space-x-2">
                        <label className="text-sm text-slate-300">是否外链</label>
                        <input type="checkbox" className="rounded bg-slate-900 border-slate-600" />
                     </div>
                     <div className="flex items-center space-x-2">
                        <label className="text-sm text-slate-300">是否缓存</label>
                        <input type="checkbox" className="rounded bg-slate-900 border-slate-600" defaultChecked />
                     </div>
                     <div className="flex items-center space-x-2">
                        <label className="text-sm text-slate-300">显示状态</label>
                        <input type="checkbox" className="rounded bg-slate-900 border-slate-600" defaultChecked />
                     </div>
                </div>
            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newVisible ? '显示' : '隐藏'}该菜单吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, ConfirmDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, CheckSquare, Square, Shield, ChevronRight, ChevronDown } from 'lucide-react';
import { MOCK_ROLES, REGIONS, BUSINESS_TYPES, MOCK_DOMAINS } from '../constants';
import { Role } from '../types';

export const RoleManager: React.FC = () => {
  const [data, setData] = useState<Role[]>(MOCK_ROLES);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<Partial<Role>>({});
  const [activeTab, setActiveTab] = useState<'info' | 'menu' | 'data'>('info');

  // Delete Confirmation
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // --- Mock Transfer Data State (Local to Modal) ---
  const [sourceData] = useState(
    Array.from({ length: 20 }).map((_, i) => ({ id: `inst-${i}`, name: `互联网专线-电路${i+1}`, category: 'BIZ_LINE' }))
  );
  // Transfer selection states
  const [targetKeys, setTargetKeys] = useState<string[]>([]); 
  const [sourceSelected, setSourceSelected] = useState<string[]>([]);
  const [targetSelected, setTargetSelected] = useState<string[]>([]);

  // Initialize Modal Data
  useEffect(() => {
    if (isModalOpen) {
        // Reset transfer state when modal opens
        // In a real app, you would parse currentRole.bizInstanceScope to setTargetKeys
        setTargetKeys([]); 
        setSourceSelected([]);
        setTargetSelected([]);
    }
  }, [isModalOpen, currentRole]);

  // Transfer Logic
  const moveToRight = () => {
    setTargetKeys([...targetKeys, ...sourceSelected]);
    setSourceSelected([]);
  };
  const moveToLeft = () => {
    setTargetKeys(targetKeys.filter(k => !targetSelected.includes(k)));
    setTargetSelected([]);
  };

  const handleEdit = (role: Role) => {
    setCurrentRole({ ...role });
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setCurrentRole({ domainId: '1', regionScope: [], bizCategoryScope: [] });
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteId(id);
      setConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteId) {
          setData(data.filter(r => r.id !== deleteId));
      }
      setConfirmOpen(false);
      setDeleteId(null);
  };

  const handleSave = () => {
      // Mock Save Logic
      if (currentRole.id) {
          setData(data.map(r => r.id === currentRole.id ? { ...r, ...currentRole } as Role : r));
      } else {
          const newRole = { 
              ...currentRole, 
              id: Date.now().toString(),
              code: currentRole.code || `ROLE_${Date.now()}` 
          } as Role;
          setData([...data, newRole]);
      }
      setIsModalOpen(false);
  };

  // Helper to get Domain Name
  const getDomainName = (id: string) => {
      if (id === '1') return '安徽省公司';
      if (id === '2') return '合肥分公司';
      return id;
  };

  const columns = [
    { 
      header: '角色名称', 
      accessor: (row: Role) => (
          <div className="flex items-center font-medium text-slate-200">
              <Shield size={16} className="mr-2 text-blue-400" />
              {row.name}
          </div>
      )
    },
    { header: '角色编码', accessor: (row: Role) => <Badge color="gray">{row.code}</Badge> },
    { header: '所属域', accessor: (row: Role) => getDomainName(row.domainId) },
    { header: '描述', accessor: 'description' },
    {
      header: '操作',
      accessor: (row: Role) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>权限配置</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      )
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
      {/* Search Bar */}
      <Card className="shrink-0">
         <div className="flex justify-between items-center">
            <div className="flex gap-4">
                <Input placeholder="角色名称" className="w-48" />
                <Input placeholder="角色编码" className="w-48" />
                <Button icon={<Search size={16} />}>查询</Button>
            </div>
            <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16} />} onClick={handleAdd}>新增角色</Button>
         </div>
      </Card>

      {/* Role List Table */}
