import React, { useState } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, UserPlus, Key, LogOut, ChevronRight, ChevronDown, Building2 } from 'lucide-react';
import { MOCK_USERS, MOCK_ROLES, MOCK_DOMAINS } from '../constants';
import { User, Domain } from '../types';

// Recursive Tree Node Component
const OrgTreeNode: React.FC<{ domain: Domain; depth?: number }> = ({ domain, depth = 0 }) => {
  const [expanded, setExpanded] = useState(true);
  const hasChildren = domain.children && domain.children.length > 0;

  return (
    <div>
      <div 
        className={`flex items-center py-1.5 hover:bg-slate-800 cursor-pointer rounded px-2 ${depth === 0 ? 'text-blue-400 font-semibold' : 'text-slate-300'}`}
        style={{ paddingLeft: `${depth * 16 + 8}px` }}
        onClick={() => setExpanded(!expanded)}
      >
        <span className="mr-1 text-slate-500 w-4 flex justify-center">
            {hasChildren && (expanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />)}
            {!hasChildren && depth === 0 && <Building2 size={14} />}
        </span>
        <span className="truncate">{domain.name}</span>
      </div>
      {hasChildren && expanded && (
        <div>
          {domain.children!.map(child => (
            <OrgTreeNode key={child.id} domain={child} depth={depth + 1} />
          ))}
        </div>
      )}
    </div>
  );
};

export const UserManager: React.FC = () => {
  const [data, setData] = useState<User[]>(MOCK_USERS);
