            onClose={() => setIsModalOpen(false)}
            title="新增用户"
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={() => setIsModalOpen(false)}>确定</Button>
                </>
              }
        >
            <div className="grid grid-cols-2 gap-4">
                <Input label="用户名" placeholder="登录账号" />
                <Input label="姓名" placeholder="真实姓名" />
                <Input label="手机号" placeholder="11位手机号" />
                <Input label="邮箱" placeholder="Email" />
                <Select label="主归属域" options={[{label: '安徽省公司', value: '1'}, {label: '合肥分公司', value: '2'}]} />
                <Select label="状态" options={[{label: '正常', value: 'active'}, {label: '锁定', value: 'locked'}]} />
            </div>

            <div className="mt-6 border-t border-slate-700 pt-4">
                <div className="flex justify-between items-center mb-2">
                    <h4 className="font-bold text-slate-200">角色配置 (支持跨域)</h4>
                    <Button size="sm" variant="ghost" className="text-blue-400" onClick={addRoleRow}><Plus size={14} className="mr-1"/>添加行</Button>
                </div>

                <div className="space-y-2">
                    {roleRows.map((row, idx) => (
                        <div key={idx} className="flex gap-4 items-center bg-slate-900/50 p-2 rounded border border-slate-700">
                            <Select 
                                className="flex-1 text-sm" 
                                options={[{label: '请选择域...', value: ''}, {label: '安徽省公司', value: '1'}, {label: '合肥分公司', value: '2'}]} 
                            />
                            <Select 
                                className="flex-1 text-sm" 
                                options={[{label: '请选择角色...', value: ''}, {label: '超级管理员', value: '1'}, {label: '业务主管', value: '2'}, {label: '运维专员', value: '3'}]} 
                            />
                            <Button size="sm" variant="ghost" className="text-red-400" onClick={() => removeRoleRow(idx)}><Trash2 size={16} /></Button>
                        </div>
                    ))}
                </div>
            </div>

            <div className="mt-4 p-3 bg-blue-900/10 border border-blue-900/30 rounded text-xs text-blue-300">
                提示：跨域用户可在此配置多个域下的不同角色。用户登录后可切换上下文。
            </div>
        </Modal>

        <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '解锁' : '锁定'}该用户吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除用户"
         message="确定要删除该用户吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

export enum UserType {
  SUPER_ADMIN = 'SUPER_ADMIN',
  ADMIN = 'ADMIN',
  CROSS_DOMAIN_USER = 'CROSS_DOMAIN_USER',
  DOMAIN_USER = 'DOMAIN_USER'
}

export interface Domain {
  id: string;
  name: string;
  code: string;
  parentId: string | null;
  manager: string;
  businessTypes: string[];
  status: 'active' | 'inactive';
  createTime: string;
  children?: Domain[];
  customerIds?: string[];
}

export interface Menu {
  id: string;
  name: string;
  type: 'dir' | 'menu' | 'button';
  parentId: string | null;
  path?: string;
  component?: string;
  permission?: string;
  icon?: string;
  sort: number;
  visible: boolean;
  children?: Menu[];
}

export interface Role {
  id: string;
  name: string;
  code: string;
  domainId: string;
  description: string;
  regionScope?: string[]; // e.g., ['0551', '0553']
  bizCategoryScope?: string[];
  bizInstanceScope?: string[];
}

export interface UserRoleRelation {
  roleId: string;
  targetDomainId: string;
}

export interface User {
  id: string;
  username: string;
  realName: string;
  phone: string;
  email: string;
  status: 'active' | 'locked';
  baseDomainId: string;
  createTime: string;
  roles: UserRoleRelation[]; // Support cross-domain roles
}

export interface BusinessInstance {
  id: string;
  name: string;
  categoryCode: string; // e.g., 'BIZ_LINE'
}

// UI Types
export interface NavItem {
  id: string;
  title: string;
  icon: any;
}

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, SearchSelect } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Building2, GitFork, ChevronLeft, ChevronRight, ChevronsRight, ChevronsLeft } from 'lucide-react';
import { MOCK_DOMAINS, BUSINESS_TYPES } from '../constants';
import { Domain } from '../types';

// Mock Customer Data for Selection
const MOCK_CUSTOMERS = [
  { id: 'c1', name: '安徽省电力公司', code: 'AH_POWER' },
  { id: 'c2', name: '江淮汽车集团', code: 'JAC_MOTORS' },
  { id: 'c3', name: '科大讯飞股份有限公司', code: 'IFLYTEK' },
  { id: 'c4', name: '合肥百货大楼集团', code: 'HF_DEPT' },
  { id: 'c5', name: '安徽海螺水泥', code: 'CONCH_CEMENT' },
  { id: 'c6', name: '铜陵有色金属', code: 'TNMG' },
  { id: 'c7', name: '阳光电源股份有限公司', code: 'SUNGROW' },
  { id: 'c8', name: '蔚来汽车（安徽）', code: 'NIO_AH' },
  { id: 'c9', name: '京东方科技集团', code: 'BOE_TECH' },
  { id: 'c10', name: '长鑫存储技术', code: 'CXMT' },
  { id: 'c11', name: '国元证券', code: 'GUOYUAN' },
  { id: 'c12', name: '华安证券', code: 'HUAAN' },
  { id: 'c13', name: '奇瑞汽车', code: 'CHERY' },
  { id: 'c14', name: '古井贡酒', code: 'GUJING' },
  { id: 'c15', name: '口子窖', code: 'KOUZI' },
  { id: 'c16', name: '迎驾贡酒', code: 'YINGJIA' },
];

const ITEMS_PER_PAGE = 8;

export const DomainManager: React.FC = () => {
  const [data, setData] = useState<Domain[]>(MOCK_DOMAINS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentDomain, setCurrentDomain] = useState<Partial<Domain> | null>(null);
  const [creationType, setCreationType] = useState<'company' | 'department'>('department');

  // Status Confirm State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);

  // Delete Confirm State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Domain | null>(null);

  // Transfer State
  const [transferSearch, setTransferSearch] = useState('');
  const [transferPage, setTransferPage] = useState(1);
  const [selectedSource, setSelectedSource] = useState<string[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<string[]>([]);

  // Helper to flatten tree for table display and parent selection
  const flattenDomains = (domains: Domain[], depth = 0): (Domain & { depth: number })[] => {
    let result: (Domain & { depth: number })[] = [];
    domains.forEach(d => {
      result.push({ ...d, depth });
      if (d.children) {
        result = result.concat(flattenDomains(d.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = flattenDomains(data);

  const handleEdit = (domain: Domain) => {
    setCurrentDomain({ ...domain, customerIds: domain.customerIds || [] });
    setCreationType(domain.parentId ? 'department' : 'company');
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    const defaultType = data.length > 0 ? 'department' : 'company';
    setCreationType(defaultType);
    setCurrentDomain({ 
      status: 'active', 
      businessTypes: [], 
      parentId: defaultType === 'department' ? (flatData[0]?.id || '') : null,
      customerIds: []
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleDelete = (row: Domain) => {
    // Check for children
    if (row.children && row.children.length > 0) {
        alert("该域包含下级节点，请先删除下级节点！");
        return;
    }
    setDeleteTarget(row);
    setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
    if (deleteTarget) {
        const removeNode = (nodes: Domain[]): Domain[] => {
            return nodes.filter(n => n.id !== deleteTarget.id).map(n => ({
                ...n,
                children: n.children ? removeNode(n.children) : []
            }));
        };
        setData(removeNode(data));
    }
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);
  };

  const handleTypeChange = (type: 'company' | 'department') => {
    setCreationType(type);
    if (type === 'company') {
      setCurrentDomain(prev => ({ ...prev, parentId: null, name: '', code: '' }));
    } else {
      setCurrentDomain(prev => ({ ...prev, parentId: flatData[0]?.id || '', name: '', code: '' }));
    }
  };

  const initiateStatusChange = (domain: Domain, checked: boolean) => {
     setTargetStatusChange({
         id: domain.id,
         newStatus: checked ? 'active' : 'inactive'
     });
     setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          const updateStatus = (items: Domain[]): Domain[] => {
              return items.map(item => {
                  if (item.id === targetStatusChange.id) {
                      return { ...item, status: targetStatusChange.newStatus };
                  }
                  if (item.children) {
                      return { ...item, children: updateStatus(item.children) };
                  }
                  return item;
              });
          };
          setData(updateStatus(data));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const handleSave = () => {
      // Mock Save
      setIsModalOpen(false);
      // Logic to update `data` state would go here in a real app
      // For now we just close the modal as the data manipulation is complex for this mock
      if (currentDomain?.id) {
          // Update
           const updateNode = (nodes: Domain[]): Domain[] => {
              return nodes.map(n => {
                  if (n.id === currentDomain.id) {
                      return { ...n, ...currentDomain } as Domain;
                  }
                  if (n.children) {
                      return { ...n, children: updateNode(n.children) };
                  }
                  return n;
              });
          };
          setData(updateNode(data));
      } else {
          // Create (Push to root or parent)
          const newDomain = {
              ...currentDomain,
              id: Date.now().toString(),
              createTime: new Date().toLocaleString()
          } as Domain;

          if (newDomain.parentId) {
              const addToParent = (nodes: Domain[]): Domain[] => {
                  return nodes.map(n => {
                      if (n.id === newDomain.parentId) {
                          return { ...n, children: [...(n.children || []), newDomain] };
                      }
                      if (n.children) {
                          return { ...n, children: addToParent(n.children) };
                      }
                      return n;
                  });
              };
              setData(addToParent(data));
          } else {
              setData([...data, newDomain]);
          }
      }
  };

  // --- Transfer Logic ---
  const currentCustomerIds = currentDomain?.customerIds || [];

  const availableCustomers = useMemo(() => {
    return MOCK_CUSTOMERS.filter(c => !currentCustomerIds.includes(c.id));
  }, [currentCustomerIds]);

  const filteredSource = useMemo(() => {
    return availableCustomers.filter(c => c.name.toLowerCase().includes(transferSearch.toLowerCase()));
  }, [availableCustomers, transferSearch]);

  const totalPages = Math.ceil(filteredSource.length / ITEMS_PER_PAGE);
  const currentSourcePage = filteredSource.slice((transferPage - 1) * ITEMS_PER_PAGE, transferPage * ITEMS_PER_PAGE);

  const handleSelectAllSource = (checked: boolean) => {
    if (checked) {
        // Select all filtered items (not just current page, to support "Direct Select All")
        const allFilteredIds = filteredSource.map(c => c.id);
        setSelectedSource([...new Set([...selectedSource, ...allFilteredIds])]);
    } else {
        // Deselect all filtered
        const filteredIds = filteredSource.map(c => c.id);
        setSelectedSource(selectedSource.filter(id => !filteredIds.includes(id)));
    }
  };

  const moveToTarget = () => {
    const newIds = [...currentCustomerIds, ...selectedSource];
    setCurrentDomain(prev => ({ ...prev, customerIds: newIds }));
    setSelectedSource([]);
  };

  const moveToSource = () => {
    const newIds = currentCustomerIds.filter(id => !selectedTarget.includes(id));
    setCurrentDomain(prev => ({ ...prev, customerIds: newIds }));
    setSelectedTarget([]);
  };

  // --- Render ---

  const columns = [
    { 
      header: '域名称', 
      accessor: (row: any) => (
        <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center">
           {row.depth === 0 ? <Building2 size={16} className="text-blue-400 mr-2"/> : <GitFork size={16} className="text-slate-500 mr-2"/>}
           <span className={`font-medium ${row.depth === 0 ? 'text-blue-100' : 'text-slate-300'}`}>{row.name}</span>
           {row.depth === 0 && <Badge color="blue" className="ml-2 scale-90">公司</Badge>}
        </div>
      ) 
    },
    { header: '域编码', accessor: 'code' },
    { header: '管理员', accessor: 'manager' },
    { 
      header: '开通业务', 
      accessor: (row: Domain) => (
        <div className="flex gap-1 flex-wrap">
          {row.businessTypes.map(bt => {
             const label = BUSINESS_TYPES.find(b => b.code === bt)?.name || bt;
             return <Badge key={bt} color="gray">{label}</Badge>;
          })}
        </div>
      ) 
    },
    { 
      header: '状态', 
      accessor: (row: Domain) => (
        <Switch 
            checked={row.status === 'active'} 
            onChange={(checked) => initiateStatusChange(row, checked)} 
        />
      ) 
    },
    { header: '创建时间', accessor: 'createTime' },
    {
      header: '操作',
      accessor: (row: Domain) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row)}>删除</Button>
        </div>
      )
    }
  ];

  const parentOptions = flatData
    .filter(d => d.id !== currentDomain?.id)
    .map(d => ({
      label: '　'.repeat(d.depth) + d.name,
      value: d.id
    }));

  return (
    <div className="space-y-4 h-full flex flex-col">
      <Card className="shrink-0">
        <div className="flex flex-wrap gap-4 items-end">
           <Input label="域名称" placeholder="输入名称" className="w-48" />
           <Input label="域编码" placeholder="输入编码" className="w-48" />
           <Select label="状态" options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '禁用', value: 'inactive'}]} className="w-32" />
           <div className="flex gap-2 pb-0.5">
             <Button icon={<Search size={16} />}>查询</Button>
             <Button variant="secondary" icon={<RotateCcw size={16} />}>重置</Button>
             <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16} />} onClick={handleAdd}>新增域</Button>
           </div>
        </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col" title="组织架构列表">
         <div className="flex-1 overflow-auto">
            <Table columns={columns} data={flatData} />
         </div>
         <div className="py-2 border-t border-slate-700 flex justify-end text-sm text-slate-400">
            共 {flatData.length} 条
         </div>
      </Card>

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={currentDomain?.id ? "编辑域信息" : "新增域"}
        size="lg"
        footer={
          <>
            <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
            <Button onClick={handleSave}>确定</Button>
          </>
        }
      >
        <div className="space-y-4">
           {/* Basic Info */}
           <div className="grid grid-cols-2 gap-4">
             <div className="col-span-2 bg-slate-900/50 p-3 rounded border border-slate-700">
                <label className="text-sm font-medium text-slate-300 mb-2 block">节点类型</label>
                <div className="flex space-x-6">
                    <label className={`flex items-center space-x-2 cursor-pointer ${currentDomain?.id ? 'opacity-50 cursor-not-allowed' : ''}`}>
                        <input 
                            type="radio" 
                            name="nodeType" 
                            checked={creationType === 'company'} 
                            onChange={() => !currentDomain?.id && handleTypeChange('company')}
                            disabled={!!currentDomain?.id}
                            className="text-blue-500 bg-slate-900 border-slate-600 focus:ring-blue-500" 
                        />
                        <span className={creationType === 'company' ? 'text-white font-medium' : 'text-slate-400'}>
                            一级公司 (租户)
                        </span>
                    </label>
                    <label className={`flex items-center space-x-2 cursor-pointer ${currentDomain?.id ? 'opacity-50 cursor-not-allowed' : ''}`}>
                        <input 
                            type="radio" 
                            name="nodeType" 
                            checked={creationType === 'department'} 
                            onChange={() => !currentDomain?.id && handleTypeChange('department')}
                            disabled={!!currentDomain?.id}
                            className="text-blue-500 bg-slate-900 border-slate-600 focus:ring-blue-500" 
                        />
                        <span className={creationType === 'department' ? 'text-white font-medium' : 'text-slate-400'}>
                            下级部门/分公司
                        </span>
                    </label>
                </div>
            </div>

            <div className="col-span-1">
                <Input 
                    label="域名称" 
                    value={currentDomain?.name || ''}
                    onChange={(e) => setCurrentDomain(prev => ({...prev, name: e.target.value}))}
                    placeholder="请输入域名称" 
                />
            </div>

            <div className="col-span-1">
                <Input 
                    label="域编码" 
                    value={currentDomain?.code || ''} 
                    onChange={(e) => setCurrentDomain(prev => ({ ...prev, code: e.target.value }))}
                    placeholder="唯一标识 (Code)" 
                    disabled={!!currentDomain?.id} 
                />
            </div>

            {creationType === 'department' && (
               <div className="col-span-2">
                   <Select 
                     label="归属上级 (公司/部门)" 
                     options={parentOptions} 
                     value={currentDomain?.parentId || ''}
                     onChange={(e) => setCurrentDomain(prev => ({ ...prev, parentId: e.target.value }))}
                   />
               </div>
            )}

           <div className="col-span-1">
             <Input label="管理员账号" defaultValue={currentDomain?.manager} placeholder="关联初始管理员" />
           </div>

           <div className="col-span-2">
             <label className="text-sm font-medium text-slate-300 mb-2 block">开通业务类型</label>
             <div className="flex flex-wrap gap-4">
               {BUSINESS_TYPES.map(bt => (
                 <label key={bt.code} className="flex items-center space-x-2 p-2 rounded border border-slate-700 hover:bg-slate-800 cursor-pointer">
                   <input type="checkbox" className="rounded border-slate-600 bg-slate-900 text-blue-600" defaultChecked={currentDomain?.businessTypes?.includes(bt.code)} />
                   <span className="text-sm text-slate-300">{bt.name}</span>
                 </label>
               ))}
             </div>
           </div>
          </div>

           {/* Customer Transfer Frame (Only for Company type or if needed) */}
           <div className="border-t border-slate-700 pt-4">
               <label className="text-sm font-medium text-slate-300 mb-2 block">关联客户 (多选)</label>

               <div className="flex h-[320px] gap-4">
                  {/* Left: Source */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg space-y-2">
                         <div className="flex gap-2">
                             <Input 
                                placeholder="搜索客户..." 
                                className="h-8 text-sm py-1" 
                                value={transferSearch}
                                onChange={(e) => { setTransferSearch(e.target.value); setTransferPage(1); }}
                             />
                         </div>
                         <div className="flex justify-between items-center px-1">
                             <label className="flex items-center space-x-2 cursor-pointer text-xs text-slate-300 select-none">
                                <input 
                                    type="checkbox" 
                                    className="rounded bg-slate-900 border-slate-600 text-blue-500" 
                                    onChange={(e) => handleSelectAllSource(e.target.checked)}
                                    checked={filteredSource.length > 0 && filteredSource.every(c => selectedSource.includes(c.id))}
                                />
                                <span>全选 ({filteredSource.length})</span>
                             </label>
                             <span className="text-xs text-slate-500">{selectedSource.length} 已选</span>
                         </div>
                      </div>

                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {currentSourcePage.map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedSource.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedSource.includes(item.id)
                                      ? setSelectedSource(selectedSource.filter(id => id !== item.id))
                                      : setSelectedSource([...selectedSource, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedSource.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                         {filteredSource.length === 0 && <div className="text-center py-4 text-xs text-slate-500">无匹配数据</div>}
                      </div>

                      {/* Pagination Controls */}
                      {totalPages > 1 && (
                          <div className="p-2 border-t border-slate-700 flex justify-between items-center bg-slate-800/30">
                              <button disabled={transferPage === 1} onClick={() => setTransferPage(p => p - 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronLeft size={16}/></button>
                              <span className="text-xs text-slate-400">{transferPage} / {totalPages}</span>
                              <button disabled={transferPage === totalPages} onClick={() => setTransferPage(p => p + 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronRight size={16}/></button>
                          </div>
                      )}
                  </div>

                  {/* Actions */}
                  <div className="flex flex-col justify-center gap-3">
                        <Button size="sm" variant="secondary" onClick={moveToTarget} disabled={selectedSource.length === 0} title="添加" className="w-10">
                            <ChevronsRight size={18} />
                        </Button>
                        <Button size="sm" variant="secondary" onClick={moveToSource} disabled={selectedTarget.length === 0} title="移除" className="w-10">
                            <ChevronsLeft size={18} />
                        </Button>
                  </div>

                  {/* Right: Target */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[76px]">
                          <span className="text-xs font-semibold text-slate-300 pl-1">已关联客户 ({currentCustomerIds.length})</span>
                          <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setCurrentDomain(prev => ({...prev, customerIds: []}))}>清空</Button>
                      </div>
                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {MOCK_CUSTOMERS.filter(c => currentCustomerIds.includes(c.id)).map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedTarget.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedTarget.includes(item.id)
                                      ? setSelectedTarget(selectedTarget.filter(id => id !== item.id))
                                      : setSelectedTarget([...selectedTarget, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedTarget.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                      </div>
                  </div>
               </div>
           </div>

           <Input label="备注" />
        </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '禁用'}该域吗？此操作可能会影响该域下所有用户的访问权限。`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除域"
         message={`确定要删除“${deleteTarget?.name}”吗？此操作不可恢复。`}
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTarget(null); }}
      />
    </div>
  );
};

