export const UserManager: React.FC = () => {
  const [data, setData] = useState<User[]>(MOCK_USERS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [roleRows, setRoleRows] = useState([{ domainId: '', roleId: '' }]);

  // Status Change Dialog State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);

  // Delete Dialog State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  const addRoleRow = () => setRoleRows([...roleRows, { domainId: '', roleId: '' }]);
  const removeRoleRow = (idx: number) => setRoleRows(roleRows.filter((_, i) => i !== idx));

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setData(data.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setData(data.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const columns = [
    { header: '用户名', accessor: 'username' },
    { header: '姓名', accessor: 'realName' },
    { header: '手机号', accessor: 'phone' },
    { header: '归属域', accessor: (row: User) => row.baseDomainId === '1' ? '安徽省公司' : '合肥分公司' },
    { 
      header: '角色列表', 
      accessor: (row: User) => (
        <div className="flex gap-1 flex-wrap">
            {row.roles.map((r, i) => (
                <Badge key={i} color="blue">
                    {MOCK_ROLES.find(role => role.id === r.roleId)?.name || r.roleId}
                    <span className="text-[10px] ml-1 opacity-70">({r.targetDomainId === '1' ? '省' : '合肥'})</span>
                </Badge>
            ))}
        </div>
      )
    },
    { 
      header: '状态', 
      accessor: (row: User) => (
        <Switch 
          checked={row.status === 'active'} 
          onChange={(checked) => initiateStatusChange(row, checked)} 
        />
      )
    },
    {
      header: '操作',
      accessor: (row: User) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" title="编辑" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => setIsModalOpen(true)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" title="删除" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      )
    }
  ];

  return (
    <div className="h-full flex gap-4">
        {/* Left List: Domain Org */}
        <Card className="w-64 h-full flex flex-col" title="域列表">
            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 text-sm select-none">
                {MOCK_DOMAINS.map(domain => (
                    <DomainNode key={domain.id} domain={domain} />
                ))}
            </div>
        </Card>

        {/* Right Table */}
        <div className="flex-1 flex flex-col space-y-4">
            <Card>
                <div className="flex flex-wrap gap-4 items-end">
                    <Input label="用户名" className="w-40" />
                    <Input label="姓名" className="w-40" />
                    <Input label="手机号" className="w-40" />
                    <div className="flex gap-2 pb-0.5">
                        <Button icon={<Search size={16} />}>查询</Button>
                        <Button variant="secondary" icon={<RotateCcw size={16} />}>重置</Button>
                        <Button className="bg-green-600 hover:bg-green-500" icon={<UserPlus size={16} />} onClick={() => setIsModalOpen(true)}>新增用户</Button>
                    </div>
                </div>
            </Card>

            <Card className="flex-1 overflow-hidden flex flex-col">
                 <div className="flex-1 overflow-auto">
                    <Table columns={columns} data={data} />
                 </div>
            </Card>
        </div>

        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title="新增用户"
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={() => setIsModalOpen(false)}>确定</Button>
                </>
              }
        >
            <div className="grid grid-cols-2 gap-4">
                <Input label="用户名" placeholder="登录账号" />
                <Input label="姓名" placeholder="真实姓名" />
                <Input label="手机号" placeholder="11位手机号" />
                <Input label="邮箱" placeholder="Email" />
                <Select label="主归属域" options={[{label: '安徽省公司', value: '1'}, {label: '合肥分公司', value: '2'}]} />
                <Select label="状态" options={[{label: '正常', value: 'active'}, {label: '锁定', value: 'locked'}]} />
            </div>

            <div className="mt-6 border-t border-slate-700 pt-4">
                <div className="flex justify-between items-center mb-2">
                    <h4 className="font-bold text-slate-200">角色配置 (支持跨域)</h4>
                    <Button size="sm" variant="ghost" className="text-blue-400" onClick={addRoleRow}><Plus size={14} className="mr-1"/>添加行</Button>
                </div>

                <div className="space-y-2">
                    {roleRows.map((row, idx) => (
                        <div key={idx} className="flex gap-4 items-center bg-slate-900/50 p-2 rounded border border-slate-700">
                            <Select 
                                className="flex-1 text-sm" 
                                options={[{label: '请选择域...', value: ''}, {label: '安徽省公司', value: '1'}, {label: '合肥分公司', value: '2'}]} 
                            />
                            <Select 
                                className="flex-1 text-sm" 
                                options={[{label: '请选择角色...', value: ''}, {label: '超级管理员', value: '1'}, {label: '业务主管', value: '2'}, {label: '运维专员', value: '3'}]} 
                            />
                            <Button size="sm" variant="ghost" className="text-red-400" onClick={() => removeRoleRow(idx)}><Trash2 size={16} /></Button>
                        </div>
                    ))}
                </div>
            </div>

            <div className="mt-4 p-3 bg-blue-900/10 border border-blue-900/30 rounded text-xs text-blue-300">
                提示：跨域用户可在此配置多个域下的不同角色。用户登录后可切换上下文。
            </div>
        </Modal>

        <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '解锁' : '锁定'}该用户吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除用户"
         message="确定要删除该用户吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

export enum UserType {
  SUPER_ADMIN = 'SUPER_ADMIN',
  ADMIN = 'ADMIN',
  CROSS_DOMAIN_USER = 'CROSS_DOMAIN_USER',
  DOMAIN_USER = 'DOMAIN_USER'
}

export type DomainMode = 'fusion' | 'switching';

export interface Domain {
  id: string;
  name: string;
  code: string;
  parentId: string | null;
  manager: string;
  businessTypes: string[];
  status: 'active' | 'inactive';
  createTime: string;
  children?: Domain[];
  customerIds?: string[];
  managementMode: DomainMode; // Updated: 'fusion' or 'switching'
  isSuper?: boolean; // New: Identifies the system default super domain
}

export interface Menu {
  id: string;
  name: string;
  type: 'dir' | 'menu' | 'button';
  parentId: string | null;
  path?: string;
  component?: string;
  permission?: string;
  icon?: string;
  sort: number;
  visible: boolean;
  children?: Menu[];
}

export interface Role {
  id: string;
  name: string;
  code: string;
  domainId: string;
  description: string;
  regionScope?: string[]; // e.g., ['0551', '0553']
  bizCategoryScope?: string[];
  bizInstanceScope?: string[];
}

export interface UserRoleRelation {
  roleId: string;
  targetDomainId: string;
  roleName?: string; // Optional for UI convenience
}

export interface User {
  id: string;
  username: string;
  realName: string;
  phone: string;
  email: string;
  status: 'active' | 'locked';
  baseDomainId: string;
  createTime: string;
  roles: UserRoleRelation[]; // Support cross-domain roles
}

export interface BusinessInstance {
  id: string;
  name: string;
  categoryCode: string; // e.g., 'BIZ_LINE'
}

// UI Types
export interface NavItem {
  id: string;
  title: string;
  icon: any;
  children?: NavItem[];
}

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Building2, ChevronLeft, ChevronRight, ChevronsRight, ChevronsLeft, Users, Repeat, Crown } from 'lucide-react';
import { MOCK_DOMAINS, MOCK_CUSTOMERS } from '../constants';
import { Domain } from '../types';

const ITEMS_PER_PAGE = 8;

export const DomainManager: React.FC = () => {
  const [data, setData] = useState<Domain[]>(MOCK_DOMAINS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentDomain, setCurrentDomain] = useState<Partial<Domain> | null>(null);

  // Status Confirm State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);

  // Delete Confirm State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Domain | null>(null);

  // Transfer State
  const [transferSearch, setTransferSearch] = useState('');
  const [transferPage, setTransferPage] = useState(1);
  const [selectedSource, setSelectedSource] = useState<string[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<string[]>([]);

  // Flat data usage
  const flatData = data;

  const handleEdit = (domain: Domain) => {
    // If Super Domain, ensure we load all customers conceptually, but user might want to edit properties
    setCurrentDomain({ 
      ...domain, 
      customerIds: domain.customerIds || [],
      managementMode: domain.managementMode || 'switching'
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setCurrentDomain({ 
      status: 'active', 
      businessTypes: [], 
      parentId: null,
      customerIds: [],
      managementMode: 'switching',
      isSuper: false
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleDelete = (row: Domain) => {
    if (row.isSuper) return; // Cannot delete super domain
    setDeleteTarget(row);
    setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
    if (deleteTarget) {
        setData(data.filter(n => n.id !== deleteTarget.id));
    }
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);
  };

  const initiateStatusChange = (domain: Domain, checked: boolean) => {
     if (domain.isSuper) return; // Cannot disable super domain
     setTargetStatusChange({
         id: domain.id,
         newStatus: checked ? 'active' : 'inactive'
     });
     setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          setData(data.map(item => item.id === targetStatusChange.id ? { ...item, status: targetStatusChange.newStatus } : item));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const handleSave = () => {
      setIsModalOpen(false);
      if (currentDomain?.id) {
          // Update
          setData(data.map(n => n.id === currentDomain.id ? { ...n, ...currentDomain } as Domain : n));
      } else {
          // Create
          const newDomain = {
              ...currentDomain,
              id: Date.now().toString(),
              createTime: new Date().toLocaleString(),
              parentId: null
          } as Domain;
          setData([...data, newDomain]);
      }
  };

  // --- Transfer Logic ---
  const currentCustomerIds = currentDomain?.customerIds || [];

  const availableCustomers = useMemo(() => {
    return MOCK_CUSTOMERS.filter(c => !currentCustomerIds.includes(c.id));
  }, [currentCustomerIds]);

  const filteredSource = useMemo(() => {
    return availableCustomers.filter(c => c.name.toLowerCase().includes(transferSearch.toLowerCase()));
  }, [availableCustomers, transferSearch]);

  const totalPages = Math.ceil(filteredSource.length / ITEMS_PER_PAGE);
  const currentSourcePage = filteredSource.slice((transferPage - 1) * ITEMS_PER_PAGE, transferPage * ITEMS_PER_PAGE);

  const handleSelectAllSource = (checked: boolean) => {
    if (checked) {
        const allFilteredIds = filteredSource.map(c => c.id);
        setSelectedSource([...new Set([...selectedSource, ...allFilteredIds])]);
    } else {
        const filteredIds = filteredSource.map(c => c.id);
        setSelectedSource(selectedSource.filter(id => !filteredIds.includes(id)));
    }
  };

  const moveToTarget = () => {
    const newIds = [...currentCustomerIds, ...selectedSource];
    setCurrentDomain(prev => ({ ...prev, customerIds: newIds }));
    setSelectedSource([]);
  };

  const moveToSource = () => {
    const newIds = currentCustomerIds.filter(id => !selectedTarget.includes(id));
    setCurrentDomain(prev => ({ ...prev, customerIds: newIds }));
    setSelectedTarget([]);
  };

  // --- Render ---

  const columns = [
    { 
      header: '域名称', 
      accessor: (row: Domain) => (
        <div className="flex items-center">
           {row.isSuper ? (
             <Crown size={16} className="text-yellow-500 mr-2" />
           ) : (
             <Building2 size={16} className="text-blue-400 mr-2"/>
           )}
           <span className={`font-medium ${row.isSuper ? 'text-yellow-100' : 'text-blue-100'}`}>{row.name}</span>
           {row.isSuper && <Badge color="yellow" className="ml-2 scale-90">系统超级域</Badge>}
        </div>
      ) 
    },
    { header: '域编码', accessor: 'code' },
    { header: '管理员', accessor: 'manager' },
    {
      header: '管理模式',
      accessor: (row: Domain) => (
         row.managementMode === 'fusion' ? (
           <Badge color="blue" className="flex items-center gap-1 w-fit">
              <Users size={10} /> 跨域融合
           </Badge>
         ) : (
           <Badge color="gray" className="flex items-center gap-1 w-fit">
              <Repeat size={10} /> 按域切换
           </Badge>
         )
      )
    },
    { 
      header: '关联客户', 
      accessor: (row: Domain) => {
        if (row.isSuper) {
             return <span className="text-slate-400 text-xs italic">所有客户权限</span>;
        }
        const ids = row.customerIds || [];
        if (ids.length === 0) return <span className="text-slate-500">-</span>;

        // Find names
        const names = ids.map(id => MOCK_CUSTOMERS.find(c => c.id === id)?.name).filter(Boolean) as string[];
        const displayCount = 2;
        const visibleNames = names.slice(0, displayCount);
        const diff = names.length - displayCount;

        return (
          <div className="flex items-center gap-1" title={names.join('、')}>
            <span className="text-slate-300 text-sm truncate max-w-[200px]">{visibleNames.join('、')}</span>
            {diff > 0 && <Badge color="gray" className="scale-90">+{diff}</Badge>}
          </div>
        )
      } 
    },
    { 
      header: '状态', 
