  const renderContent = () => {
    switch (activePage) {
      case 'domain': return <DomainManager />;
      case 'menu': return <MenuManager />;
      case 'role': return <RoleManager />;
      case 'user': return <UserManager />;
      case 'demo_mode': return <DemoMode />;
      default: return null;
    }
  };

