          } else {
              return (
                  <div className="flex items-center pl-10 text-slate-300">
                      <div className="w-[1px] h-4 bg-slate-700 mr-3 absolute left-6"></div> {/* Indent guide */}
                      <Shield size={16} className="mr-2 text-green-500" />
                      <span className="font-medium">{row.data.name}</span>
                  </div>
              );
          }
