      accessor: (row: TreeItem) => row.type === 'role' ? <Badge color="gray">{row.data.code}</Badge> : <span className="text-slate-600 text-xs italic">{row.data.code}</span>,
      width: '20%'
    },
    { 
      header: '描述', 
      accessor: (row: TreeItem) => row.type === 'role' ? row.data.description : '',
