  return (
    <div 
      className={`flex items-center py-2 hover:bg-slate-800 cursor-pointer rounded px-2 text-slate-300`}
    >
      <Building2 size={14} className="mr-2 text-blue-500" />
      <span className="truncate">{domain.name}</span>
