};

export const UserManager: React.FC = () => {
  const [data, setData] = useState<User[]>(MOCK_USERS);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [roleRows, setRoleRows] = useState([{ domainId: '', roleId: '' }]);

  // Search State
  const [searchUsername, setSearchUsername] = useState('');
  const [searchRealName, setSearchRealName] = useState('');
  const [searchPhone, setSearchPhone] = useState('');

  // Status Change Dialog State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);

  // Delete Dialog State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // Filter Data
  const filteredData = useMemo(() => {
      return data.filter(user => {
          const matchUser = user.username.toLowerCase().includes(searchUsername.toLowerCase());
          const matchName = user.realName.toLowerCase().includes(searchRealName.toLowerCase());
          const matchPhone = user.phone.includes(searchPhone);
          return matchUser && matchName && matchPhone;
      });
  }, [data, searchUsername, searchRealName, searchPhone]);

  const addRoleRow = () => setRoleRows([...roleRows, { domainId: '', roleId: '' }]);
  const removeRoleRow = (idx: number) => setRoleRows(roleRows.filter((_, i) => i !== idx));

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setData(data.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setData(data.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const columns = [
    { header: '用户名', accessor: 'username' },
    { header: '姓名', accessor: 'realName' },
    { header: '手机号', accessor: 'phone' },
    { header: '归属域', accessor: (row: User) => MOCK_DOMAINS.find(d => d.id === row.baseDomainId)?.name || row.baseDomainId },
    { 
      header: '角色列表', 
      accessor: (row: User) => (
        <div className="flex gap-1 flex-wrap">
            {row.roles.map((r, i) => (
                <Badge key={i} color="blue">
                    {MOCK_ROLES.find(role => role.id === r.roleId)?.name || r.roleId}
                    <span className="text-[10px] ml-1 opacity-70">
                        ({MOCK_DOMAINS.find(d => d.id === r.targetDomainId)?.name.substring(0, 4) || '未知'})
                    </span>
                </Badge>
            ))}
        </div>
      )
    },
    { 
      header: '状态', 
      accessor: (row: User) => (
        <Switch 
          checked={row.status === 'active'} 
          onChange={(checked) => initiateStatusChange(row, checked)} 
        />
      )
    },
    {
      header: '操作',
      accessor: (row: User) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" title="编辑" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => setIsModalOpen(true)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" title="删除" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      )
    }
  ];

  return (
    <div className="h-full flex gap-4">
        {/* Left List: Domain Org */}
        <Card className="w-64 h-full flex flex-col" title="域列表">
            <div className="flex-1 overflow-y-auto custom-scrollbar p-2 text-sm select-none">
                {MOCK_DOMAINS.map(domain => (
                    <DomainNode key={domain.id} domain={domain} />
                ))}
            </div>
        </Card>

        {/* Right Table */}
        <div className="flex-1 flex flex-col space-y-4">
            <Card>
                <div className="flex flex-wrap gap-4 items-end">
                    <Input 
                        label="用户名" 
                        className="w-40" 
                        value={searchUsername} 
                        onChange={e => setSearchUsername(e.target.value)} 
                    />
                    <Input 
                        label="姓名" 
                        className="w-40" 
                        value={searchRealName}
                        onChange={e => setSearchRealName(e.target.value)}
                    />
                    <Input 
                        label="手机号" 
                        className="w-40" 
                        value={searchPhone}
                        onChange={e => setSearchPhone(e.target.value)}
                    />
                    <div className="flex gap-2 pb-0.5">
                        <Button icon={<Search size={16} />}>查询</Button>
                        <Button 
                            variant="secondary" 
                            icon={<RotateCcw size={16} />} 
                            onClick={() => { setSearchUsername(''); setSearchRealName(''); setSearchPhone(''); }}
                        >
                            重置
                        </Button>
                        <Button className="bg-green-600 hover:bg-green-500" icon={<UserPlus size={16} />} onClick={() => setIsModalOpen(true)}>新增用户</Button>
                    </div>
                </div>
            </Card>

            <Card className="flex-1 overflow-hidden flex flex-col">
                 <div className="flex-1 overflow-auto">
                    <Table columns={columns} data={filteredData} />
                 </div>
                 <div className="py-2 border-t border-slate-700 flex justify-end text-sm text-slate-400">
                    共 {filteredData.length} 条
                 </div>
            </Card>
        </div>

        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title="新增用户"
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={() => setIsModalOpen(false)}>确定</Button>
                </>
              }
        >
            <div className="grid grid-cols-2 gap-4">
                <Input label="用户名" placeholder="登录账号" />
                <Input label="姓名" placeholder="真实姓名" />
                <Input label="手机号" placeholder="11位手机号" />
                <Input label="邮箱" placeholder="Email" />
                <Select label="主归属域" options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))} />
                <Select label="状态" options={[{label: '正常', value: 'active'}, {label: '锁定', value: 'locked'}]} />
            </div>

            <div className="mt-6 border-t border-slate-700 pt-4">
                <div className="flex justify-between items-center mb-2">
                    <h4 className="font-bold text-slate-200">角色配置 (支持跨域)</h4>
                    <Button size="sm" variant="ghost" className="text-blue-400" onClick={addRoleRow}><Plus size={14} className="mr-1"/>添加行</Button>
                </div>

                <div className="space-y-2">
                    {roleRows.map((row, idx) => (
                        <div key={idx} className="flex gap-4 items-center bg-slate-900/50 p-2 rounded border border-slate-700">
                            <Select 
                                className="flex-1 text-sm" 
                                options={[{label: '请选择域...', value: ''}, ...MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))]}
                            />
                            <Select 
                                className="flex-1 text-sm" 
                                options={[{label: '请选择角色...', value: ''}, ...MOCK_ROLES.map(r => ({ label: r.name, value: r.id }))]}
                            />
                            <Button size="sm" variant="ghost" className="text-red-400" onClick={() => removeRoleRow(idx)}><Trash2 size={16} /></Button>
                        </div>
                    ))}
                </div>
            </div>

            <div className="mt-4 p-3 bg-blue-900/10 border border-blue-900/30 rounded text-xs text-blue-300">
                提示：跨域用户可在此配置多个域下的不同角色。用户登录后可切换上下文。
            </div>
        </Modal>

        <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '解锁' : '锁定'}该用户吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除用户"
         message="确定要删除该用户吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, UserPlus, Folder, ChevronDown, ChevronRight, User as UserIcon, Mail, Phone, Shield } from 'lucide-react';
import { MOCK_USERS, MOCK_ROLES, MOCK_DOMAINS } from '../constants';
import { User, Domain, Role } from '../types';

type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; userCount: number; expanded: boolean }
  | { type: 'user'; id: string; data: User; parentDomainName: string };

export const UserManager: React.FC = () => {
  const [userData, setUserData] = useState<User[]>(MOCK_USERS);
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  // Search State
  const [searchKeyword, setSearchKeyword] = useState('');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Partial<User>>({});
  const [selectedRoleIds, setSelectedRoleIds] = useState<Set<string>>(new Set());

  // Confirm Dialogs
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // --- Tree Data Construction ---
  const flatTreeData = useMemo(() => {
      // 1. Filter Users
      const lowerSearch = searchKeyword.toLowerCase();
      const filteredUsers = userData.filter(u => 
          u.username.toLowerCase().includes(lowerSearch) || 
          u.realName.toLowerCase().includes(lowerSearch) ||
          u.phone.includes(lowerSearch)
      );

      const result: TreeItem[] = [];

      MOCK_DOMAINS.forEach(domain => {
          // Find users for this domain
          const domainUsers = filteredUsers.filter(u => u.baseDomainId === domain.id);

          // Determine if domain matches search directly
          const isDomainMatch = domain.name.toLowerCase().includes(lowerSearch);

          // If searching, show if Domain Matches OR if it has matching users
          if (searchKeyword && !isDomainMatch && domainUsers.length === 0) {
              return;
          }

          const isExpanded = expandedDomains.has(domain.id) || !!searchKeyword; // Auto expand on search

          // Add Domain Node
          result.push({
              type: 'domain',
              id: `d-${domain.id}`,
              data: domain,
              userCount: userData.filter(u => u.baseDomainId === domain.id).length, // Show total count, not just filtered
              expanded: isExpanded
          });

          // Add User Nodes
          if (isExpanded) {
              domainUsers.forEach(user => {
                  result.push({
                      type: 'user',
                      id: user.id,
                      data: user,
                      parentDomainName: domain.name
                  });
              });
          }
      });

      return result;
  }, [userData, expandedDomains, searchKeyword]);

  // --- Handlers ---

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  const handleEdit = (user: User) => {
      setCurrentUser({ ...user });
      // Extract role IDs that belong to this domain (ignoring cross-domain for now as per requirement)
      const roleIds = user.roles
        .filter(r => r.targetDomainId === user.baseDomainId) // Strict domain check
        .map(r => r.roleId);
      setSelectedRoleIds(new Set(roleIds));
      setIsModalOpen(true);
  };

  const handleAdd = () => {
      setCurrentUser({ 
          status: 'active', 
          baseDomainId: MOCK_DOMAINS[0].id // Default to first domain
      });
      setSelectedRoleIds(new Set());
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentUser.username || !currentUser.realName || !currentUser.baseDomainId) {
          alert("请完善基本信息");
          return;
      }

      // Construct Roles: All selected roles are assigned to the baseDomainId
      const newRoles = Array.from(selectedRoleIds).map(rId => {
          const roleDef = MOCK_ROLES.find(r => r.id === rId);
          return {
              roleId: rId,
              targetDomainId: currentUser.baseDomainId!,
              roleName: roleDef?.name
          };
      });

      if (currentUser.id) {
          // Update
          setUserData(userData.map(u => u.id === currentUser.id ? { ...u, ...currentUser, roles: newRoles } as User : u));
      } else {
          // Create
          const newUser = {
              ...currentUser,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              roles: newRoles
          } as User;
          setUserData([...userData, newUser]);
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setUserData(userData.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setUserData(userData.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  // --- Helpers for Modal ---
  // Get available roles for the selected domain
  const availableRoles = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return MOCK_ROLES.filter(r => r.domainId === currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  // Handle Domain Change in Modal (Reset roles if domain changes)
  const handleDomainChange = (domainId: string) => {
      setCurrentUser(prev => ({ ...prev, baseDomainId: domainId }));
      setSelectedRoleIds(new Set()); // Clear roles as they belong to specific domain
  };

  const toggleRoleSelection = (roleId: string) => {
      const newSet = new Set(selectedRoleIds);
      if (newSet.has(roleId)) newSet.delete(roleId);
      else newSet.add(roleId);
      setSelectedRoleIds(newSet);
  };


  // --- Columns ---
  const columns = [
    { 
      header: '用户 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-yellow-500 fill-yellow-500/10" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.userCount} 用户</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10">
                       {/* Tree visual lines */}
                      <div className="absolute left-[29px] w-[1px] h-full bg-transparent border-l border-slate-700/50 -top-4 bottom-0"></div>
                      <div className="relative flex items-center">
                          <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center mr-3 border border-slate-600 text-slate-300">
                              <UserIcon size={16} />
                          </div>
                          <div>
                              <div className="text-slate-200 font-medium text-sm">{row.data.realName}</div>
                              <div className="text-slate-500 text-xs">{row.data.username}</div>
                          </div>
                      </div>
                  </div>
              );
          }
      },
      width: '30%'
    },
    { 
        header: '联系方式', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            return (
                <div className="flex flex-col text-xs text-slate-400 space-y-1">
                    <div className="flex items-center"><Phone size={12} className="mr-1 opacity-70"/> {row.data.phone}</div>
                    <div className="flex items-center"><Mail size={12} className="mr-1 opacity-70"/> {row.data.email}</div>
                </div>
            )
        }
    },
    { 
        header: '关联角色 (本域)', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            // Filter roles strictly for this domain context
            const roles = row.data.roles.filter(r => r.targetDomainId === row.data.baseDomainId);
            if (roles.length === 0) return <span className="text-slate-600 text-xs italic">未分配角色</span>;

            return (
                <div className="flex gap-1 flex-wrap">
                    {roles.map((r, i) => (
                        <Badge key={i} color="blue" className="flex items-center gap-1">
                            <Shield size={10} />
                            {MOCK_ROLES.find(role => role.id === r.roleId)?.name || r.roleName || '未知角色'}
                        </Badge>
                    ))}
                </div>
            )
        } 
    },
    { 
        header: '状态', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            return (
                <Switch 
                    checked={row.data.status === 'active'} 
                    onChange={(checked) => initiateStatusChange(row.data, checked)} 
                />
            )
        },
        width: '100px'
    },
    {
      header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => {
                    setCurrentUser({ status: 'active', baseDomainId: row.data.id });
                    setSelectedRoleIds(new Set());
                    setIsModalOpen(true);
                }}>
                    新增用户
                </Button>
              )
          }
          return (
            <div className="flex space-x-2">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>编辑</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '180px'
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
        {/* Header Actions */}
        <Card className="shrink-0">
            <div className="flex justify-between items-center">
                <div className="flex gap-4 items-center">
                    <Input 
                        placeholder="搜索姓名/账号/手机号..." 
                        className="w-64" 
                        value={searchKeyword} 
                        onChange={e => setSearchKeyword(e.target.value)}
                        prefix={<Search size={16}/>}
                    />
                    <div className="flex gap-2">
                        <Button icon={<Search size={16} />}>查询</Button>
                        <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => setSearchKeyword('')}>重置</Button>
                    </div>
                </div>
                <Button className="bg-green-600 hover:bg-green-500" icon={<UserPlus size={16} />} onClick={handleAdd}>新增用户</Button>
            </div>
        </Card>

        {/* Tree Table */}
        <Card className="flex-1 overflow-hidden flex flex-col" title="用户列表 (按域分组)">
            <div className="flex-1 overflow-auto">
                <Table columns={columns} data={flatTreeData} keyField="id" />
            </div>
             <div className="py-2 border-t border-slate-700 flex justify-end text-sm text-slate-400">
                共 {userData.length} 名用户
             </div>
        </Card>

        {/* Add/Edit Modal */}
        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title={currentUser.id ? "编辑用户" : "新增用户"}
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={handleSave}>确定</Button>
                </>
              }
        >
            <div className="space-y-6">
                {/* 1. Basic Info */}
                <div>
                    <h4 className="text-sm font-bold text-slate-200 mb-3 border-l-2 border-blue-500 pl-2">基本信息</h4>
                    <div className="grid grid-cols-2 gap-4">
                        <Input 
                            label="用户名" 
                            placeholder="登录账号" 
                            value={currentUser.username || ''}
                            onChange={e => setCurrentUser({...currentUser, username: e.target.value})}
                        />
                        <Input 
                            label="真实姓名" 
                            placeholder="员工姓名" 
                            value={currentUser.realName || ''}
                            onChange={e => setCurrentUser({...currentUser, realName: e.target.value})}
                        />
                        <Input 
                            label="手机号" 
                            placeholder="11位手机号" 
                            value={currentUser.phone || ''}
                            onChange={e => setCurrentUser({...currentUser, phone: e.target.value})}
                        />
                        <Input 
                            label="邮箱" 
                            placeholder="Email" 
                            value={currentUser.email || ''}
                            onChange={e => setCurrentUser({...currentUser, email: e.target.value})}
                        />
                        <div className="col-span-2">
                             <Select 
                                label="归属域 (部门/项目组)" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentUser.baseDomainId}
                                onChange={(e) => handleDomainChange(e.target.value)}
                             />
                             <p className="text-xs text-slate-500 mt-1">切换归属域将重置已选角色。</p>
                        </div>
                         <div className="col-span-2">
                            <label className="text-sm font-medium text-slate-300 mb-1 block">账户状态</label>
                            <div className="flex items-center gap-3">
                                <span className="text-sm text-slate-400">正常</span>
                                <Switch 
                                    checked={currentUser.status === 'active'}
                                    onChange={c => setCurrentUser({...currentUser, status: c ? 'active' : 'locked'})}
                                />
                                <span className="text-sm text-slate-400">锁定</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* 2. Role Config */}
                <div>
                    <h4 className="text-sm font-bold text-slate-200 mb-3 border-l-2 border-green-500 pl-2 flex justify-between">
                        <span>角色分配</span>
                        <span className="text-xs font-normal text-slate-500 self-end">仅显示归属域 [{MOCK_DOMAINS.find(d => d.id === currentUser.baseDomainId)?.name}] 下的可用角色</span>
                    </h4>

                    <div className="bg-slate-900/50 rounded border border-slate-700 p-4 min-h-[100px]">
                        {availableRoles.length > 0 ? (
                            <div className="grid grid-cols-2 gap-3">
                                {availableRoles.map(role => (
                                    <label key={role.id} className="flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer border border-transparent hover:border-slate-600 transition-colors">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900 mr-3 h-4 w-4"
                                            checked={selectedRoleIds.has(role.id)}
                                            onChange={() => toggleRoleSelection(role.id)}
                                        />
                                        <div>
                                            <div className="text-sm text-slate-200 font-medium">{role.name}</div>
                                            <div className="text-xs text-slate-500">{role.code}</div>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-500 py-4">
                                <Shield size={24} className="mb-2 opacity-50"/>
                                <span className="text-sm">该域下暂无可用角色，请先在角色管理中配置。</span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </Modal>

        <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '解锁' : '锁定'}该用户吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除用户"
         message="确定要删除该用户吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

import React, { ReactNode, useState, useRef, useEffect } from 'react';
import { X, Check, AlertCircle, ChevronDown, Search } from 'lucide-react';

// --- Colors ---
// Using Tailwind standard palette, keeping in mind the dark blue enterprise theme.
// Primary: blue-600
// Bg: slate-900 / slate-800
// Border: slate-700

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  icon?: ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ variant = 'primary', size = 'md', icon, children, className, ...props }) => {
  const baseStyle = "inline-flex items-center justify-center rounded transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900";

  const variants = {
    primary: "bg-blue-600 hover:bg-blue-500 text-white focus:ring-blue-500",
    secondary: "bg-slate-700 hover:bg-slate-600 text-white focus:ring-slate-500 border border-slate-600",
    danger: "bg-red-600 hover:bg-red-500 text-white focus:ring-red-500",
    ghost: "bg-transparent hover:bg-slate-800 text-slate-300 hover:text-white"
  };

  const sizes = {
    sm: "px-2 py-1 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base"
  };

  return (
    <button className={`${baseStyle} ${variants[variant]} ${sizes[size]} ${className || ''}`} {...props}>
      {icon && <span className="mr-2">{icon}</span>}
      {children}
    </button>
  );
};

export const Switch: React.FC<{ checked: boolean; onChange: (checked: boolean) => void; disabled?: boolean }> = ({ checked, onChange, disabled }) => {
  return (
    <button 
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => !disabled && onChange(!checked)}
      className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-slate-900 ${checked ? 'bg-green-600' : 'bg-red-600'} ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <span className="sr-only">Use setting</span>
      <span
        aria-hidden="true"
        className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${checked ? 'translate-x-5' : 'translate-x-0'}`}
      />
    </button>
  );
};

export const Card: React.FC<{ children: ReactNode; title?: string; className?: string; action?: ReactNode }> = ({ children, title, className, action }) => (
  <div className={`bg-slate-800/50 border border-slate-700 rounded-lg shadow-sm ${className || ''}`}>
    {title && (
      <div className="px-4 py-3 border-b border-slate-700 flex justify-between items-center bg-[#0f172a]/40 rounded-t-lg">
        <h3 className="font-semibold text-slate-100">{title}</h3>
        {action && <div>{action}</div>}
      </div>
    )}
    <div className="p-4">{children}</div>
  </div>
);

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: ReactNode;
  footer?: ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, footer, size = 'md' }) => {
  if (!isOpen) return null;

  const sizes = {
    sm: 'max-w-md',
    md: 'max-w-xl',
    lg: 'max-w-3xl',
    xl: 'max-w-5xl'
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className={`bg-[#0f172a] border border-slate-700 w-full ${sizes[size]} rounded-lg shadow-2xl flex flex-col max-h-[90vh]`}>
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-700 bg-blue-900/20 rounded-t-lg">
          <h2 className="text-lg font-bold text-white">{title}</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>
        <div className="p-6 overflow-y-auto custom-scrollbar flex-1 text-slate-200">
          {children}
        </div>
        {footer && (
          <div className="px-6 py-4 border-t border-slate-700 bg-slate-800/50 flex justify-end space-x-3 rounded-b-lg">
            {footer}
          </div>
        )}
      </div>
    </div>
  );
};

interface ConfirmDialogProps {
  isOpen: boolean;
  title?: string;
  message: string;
  onConfirm: () => void;
  onCancel: () => void;
}

export const ConfirmDialog: React.FC<ConfirmDialogProps> = ({ isOpen, title = '确认操作', message, onConfirm, onCancel }) => {
  return (
    <Modal isOpen={isOpen} onClose={onCancel} title={title} size="sm" 
      footer={
        <>
           <Button variant="secondary" onClick={onCancel}>取消</Button>
           <Button variant="primary" onClick={onConfirm}>确定</Button>
