// New Component: SearchSelect (Combobox)
export const SearchSelect: React.FC<{ 
  label?: string; 
  options: { label: string; value: string; extra?: any }[]; 
  value?: string;
  onChange: (val: string, option?: any) => void;
  placeholder?: string;
  disabled?: boolean;
}> = ({ label, options, value, onChange, placeholder = '请选择...', disabled }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState('');
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
     // Sync search text with selected value label when value changes externally or initially
     const selectedOpt = options.find(o => o.value === value);
     if (selectedOpt && !isOpen) {
         setSearch(selectedOpt.label);
     } else if (!value && !isOpen) {
         setSearch('');
     }
  }, [value, options, isOpen]);

  const filteredOptions = options.filter(opt => 
    opt.label.toLowerCase().includes(search.toLowerCase())
  ).slice(0, 10); // Limit to top 10

  const handleSelect = (opt: typeof options[0]) => {
    onChange(opt.value, opt);
    setSearch(opt.label);
    setIsOpen(false);
  };

  return (
    <div className="space-y-1 relative" ref={wrapperRef}>
      {label && <label className="text-sm font-medium text-slate-300">{label}</label>}
      <div className="relative">
        <input
          type="text"
          className={`w-full px-3 py-2 bg-slate-900 border border-slate-700 rounded focus:ring-2 focus:ring-blue-500 focus:border-transparent text-white placeholder-slate-500 transition-all ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
          placeholder={placeholder}
          value={search}
          onChange={(e) => {
              setSearch(e.target.value);
              setIsOpen(true);
              if (!e.target.value) onChange('', null);
          }}
          onFocus={() => !disabled && setIsOpen(true)}
          disabled={disabled}
        />
        <ChevronDown className="absolute right-3 top-2.5 text-slate-500 pointer-events-none" size={16} />
      </div>

      {isOpen && !disabled && (
        <div className="absolute z-50 w-full mt-1 bg-slate-800 border border-slate-700 rounded shadow-lg max-h-60 overflow-y-auto custom-scrollbar">
          {filteredOptions.length > 0 ? (
            filteredOptions.map((opt) => (
              <div
                key={opt.value}
                className="px-3 py-2 text-sm text-slate-300 hover:bg-slate-700 cursor-pointer flex justify-between items-center"
                onClick={() => handleSelect(opt)}
              >
                <span>{opt.label}</span>
                {value === opt.value && <Check size={14} className="text-blue-500" />}
              </div>
            ))
          ) : (
            <div className="px-3 py-2 text-sm text-slate-500">无匹配结果</div>
          )}
        </div>
      )}
    </div>
  );
};


