import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, Building2, ChevronLeft, ChevronRight, ChevronsRight, ChevronsLeft, Users, Repeat, Crown } from 'lucide-react';
import { MOCK_DOMAINS, MOCK_CUSTOMERS } from '../constants';
import { Domain } from '../types';

const ITEMS_PER_PAGE = 8;

export const DomainManager: React.FC = () => {
  const [data, setData] = useState<Domain[]>(MOCK_DOMAINS);
  const [currentPage, setCurrentPage] = useState(1);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentDomain, setCurrentDomain] = useState<Partial<Domain> | null>(null);

  // Search State
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchStatus, setSearchStatus] = useState('');

  // Status Confirm State
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'inactive' } | null>(null);

  // Delete Confirm State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Domain | null>(null);

  // Transfer State
  const [transferSearch, setTransferSearch] = useState('');
  const [transferPage, setTransferPage] = useState(1);
  const [selectedSource, setSelectedSource] = useState<string[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<string[]>([]);

  // Filtering Data
  const filteredData = useMemo(() => {
      return data.filter(d => {
          const matchName = d.name.toLowerCase().includes(searchName.toLowerCase());
          const matchCode = d.code.toLowerCase().includes(searchCode.toLowerCase());
          const matchStatus = searchStatus ? d.status === searchStatus : true;
          return matchName && matchCode && matchStatus;
      });
  }, [data, searchName, searchCode, searchStatus]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredData.length / ITEMS_PER_PAGE);
  const paginatedData = filteredData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  const handleEdit = (domain: Domain) => {
    // If Super Domain, ensure we load all customers conceptually, but user might want to edit properties
    setCurrentDomain({ 
      ...domain, 
      customerIds: domain.customerIds || [],
      managementMode: domain.managementMode || 'switching'
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setCurrentDomain({ 
      status: 'active', 
      businessTypes: [], 
      parentId: null,
      customerIds: [],
      managementMode: 'switching',
      isSuper: false
    });
    setTransferSearch('');
    setTransferPage(1);
    setSelectedSource([]);
    setSelectedTarget([]);
    setIsModalOpen(true);
  };

  const handleDelete = (row: Domain) => {
    if (row.isSuper) return; // Cannot delete super domain
    setDeleteTarget(row);
    setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
    if (deleteTarget) {
        setData(data.filter(n => n.id !== deleteTarget.id));
    }
    setDeleteConfirmOpen(false);
    setDeleteTarget(null);
  };

  const initiateStatusChange = (domain: Domain, checked: boolean) => {
     if (domain.isSuper) return; // Cannot disable super domain
     setTargetStatusChange({
         id: domain.id,
         newStatus: checked ? 'active' : 'inactive'
     });
     setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
      if (targetStatusChange) {
          setData(data.map(item => item.id === targetStatusChange.id ? { ...item, status: targetStatusChange.newStatus } : item));
      }
      setConfirmOpen(false);
      setTargetStatusChange(null);
  };

  const handleSave = () => {
      setIsModalOpen(false);
      if (currentDomain?.id) {
          // Update
          setData(data.map(n => n.id === currentDomain.id ? { ...n, ...currentDomain } as Domain : n));
      } else {
          // Create
          const newDomain = {
              ...currentDomain,
              id: Date.now().toString(),
              createTime: new Date().toLocaleString(),
              parentId: null
          } as Domain;
          setData([...data, newDomain]);
      }
  };

  // --- Transfer Logic ---
  const currentCustomerIds = currentDomain?.customerIds || [];

  const availableCustomers = useMemo(() => {
    return MOCK_CUSTOMERS.filter(c => !currentCustomerIds.includes(c.id));
  }, [currentCustomerIds]);

  const filteredSource = useMemo(() => {
    return availableCustomers.filter(c => c.name.toLowerCase().includes(transferSearch.toLowerCase()));
  }, [availableCustomers, transferSearch]);

  const totalTransferPages = Math.ceil(filteredSource.length / ITEMS_PER_PAGE);
  const currentSourcePage = filteredSource.slice((transferPage - 1) * ITEMS_PER_PAGE, transferPage * ITEMS_PER_PAGE);

  const handleSelectAllSource = (checked: boolean) => {
    if (checked) {
        const allFilteredIds = filteredSource.map(c => c.id);
        setSelectedSource([...new Set([...selectedSource, ...allFilteredIds])]);
    } else {
        const filteredIds = filteredSource.map(c => c.id);
        setSelectedSource(selectedSource.filter(id => !filteredIds.includes(id)));
    }
  };

  const moveToTarget = () => {
    const newIds = [...currentCustomerIds, ...selectedSource];
    setCurrentDomain(prev => ({ ...prev, customerIds: newIds }));
    setSelectedSource([]);
  };

  const moveToSource = () => {
    const newIds = currentCustomerIds.filter(id => !selectedTarget.includes(id));
    setCurrentDomain(prev => ({ ...prev, customerIds: newIds }));
    setSelectedTarget([]);
  };

  // --- Render ---

  const columns = [
    { 
      header: '域名称', 
      accessor: (row: Domain) => (
        <div className="flex items-center">
           {row.isSuper ? (
             <Crown size={16} className="text-yellow-500 mr-2" />
           ) : (
             <Building2 size={16} className="text-blue-400 mr-2"/>
           )}
           <span className={`font-medium ${row.isSuper ? 'text-yellow-100' : 'text-blue-100'}`}>{row.name}</span>
           {row.isSuper && <Badge color="yellow" className="ml-2 scale-90">总控</Badge>}
        </div>
      ) 
    },
    { header: '域编码', accessor: 'code' },
    { header: '管理员', accessor: 'manager' },
    {
      header: '管理模式',
      accessor: (row: Domain) => (
         row.managementMode === 'fusion' ? (
           <Badge color="blue" className="flex items-center gap-1 w-fit">
              <Users size={10} /> 跨域融合
           </Badge>
         ) : (
           <Badge color="gray" className="flex items-center gap-1 w-fit">
              <Repeat size={10} /> 按域切换
           </Badge>
         )
      )
    },
    { 
      header: '关联客户', 
      accessor: (row: Domain) => {
        if (row.isSuper) {
             return <span className="text-slate-400 text-xs italic">所有客户权限</span>;
        }
        const ids = row.customerIds || [];
        if (ids.length === 0) return <span className="text-slate-500">-</span>;

        // Find names
        const names = ids.map(id => MOCK_CUSTOMERS.find(c => c.id === id)?.name).filter(Boolean) as string[];
        const displayCount = 2;
        const visibleNames = names.slice(0, displayCount);
        const diff = names.length - displayCount;

        return (
          <div className="flex items-center gap-1" title={names.join('、')}>
            <span className="text-slate-300 text-sm truncate max-w-[200px]">{visibleNames.join('、')}</span>
            {diff > 0 && <Badge color="gray" className="scale-90">+{diff}</Badge>}
          </div>
        )
      } 
    },
    { 
      header: '状态', 
      accessor: (row: Domain) => (
        <Switch 
            checked={row.status === 'active'} 
            onChange={(checked) => initiateStatusChange(row, checked)} 
            disabled={row.isSuper}
        />
      ) 
    },
    { header: '创建时间', accessor: 'createTime' },
    {
      header: '操作',
      accessor: (row: Domain) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          {!row.isSuper && (
            <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row)}>删除</Button>
          )}
        </div>
      )
    }
  ];

  return (
    <div className="space-y-4 h-full flex flex-col">
      <Card className="shrink-0">
        <div className="flex flex-wrap gap-4 items-end">
           <Input 
             label="域名称" 
             placeholder="输入名称" 
             className="w-48" 
             value={searchName} 
             onChange={e => { setSearchName(e.target.value); setCurrentPage(1); }} 
           />
           <Input 
             label="域编码" 
             placeholder="输入编码" 
             className="w-48" 
             value={searchCode} 
             onChange={e => { setSearchCode(e.target.value); setCurrentPage(1); }} 
           />
           <Select 
             label="状态" 
             options={[{label: '全部', value: ''}, {label: '启用', value: 'active'}, {label: '禁用', value: 'inactive'}]} 
             className="w-32" 
             value={searchStatus}
             onChange={e => { setSearchStatus(e.target.value); setCurrentPage(1); }}
           />
           <div className="flex gap-2 pb-0.5">
             <Button icon={<Search size={16} />}>查询</Button>
             <Button 
                variant="secondary" 
                icon={<RotateCcw size={16} />} 
                onClick={() => { setSearchName(''); setSearchCode(''); setSearchStatus(''); setCurrentPage(1); }}
             >
                重置
             </Button>
             <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16} />} onClick={handleAdd}>新增子域</Button>
           </div>
        </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col" title="域列表">
         <div className="flex-1 overflow-auto">
            <Table columns={columns} data={paginatedData} />
         </div>
         <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {filteredData.length} 条</div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
         </div>
      </Card>

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={currentDomain?.isSuper ? "智慧运维总控信息" : (currentDomain?.id ? "编辑子域信息" : "新增子域")}
        size="lg"
        footer={
          <>
            <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
            <Button onClick={handleSave}>确定</Button>
          </>
        }
      >
        <div className="space-y-4">
           {/* Basic Info */}
           <div className="grid grid-cols-2 gap-4">
            <div className="col-span-1">
                <Input 
                    label="域名称" 
                    value={currentDomain?.name || ''}
                    onChange={(e) => setCurrentDomain(prev => ({...prev, name: e.target.value}))}
                    placeholder="请输入域名称" 
                    disabled={currentDomain?.isSuper}
                />
            </div>

            <div className="col-span-1">
                <Input 
                    label="域编码" 
                    value={currentDomain?.code || ''} 
                    onChange={(e) => setCurrentDomain(prev => ({ ...prev, code: e.target.value }))}
                    placeholder="唯一标识 (Code)" 
                    disabled={!!currentDomain?.id} 
                />
            </div>

           <div className="col-span-2">
             <Input label="管理员账号" defaultValue={currentDomain?.manager} placeholder="关联初始管理员" />
           </div>

           {/* Management Mode Selection */}
           <div className="col-span-2 bg-slate-900/50 p-4 rounded border border-slate-700">
                <label className="text-sm font-medium text-slate-300 block mb-3">管理模式 (Management Mode)</label>
                <div className="grid grid-cols-2 gap-4">
                     <div 
                        className={`border rounded p-3 cursor-pointer transition-all flex items-start gap-3 ${currentDomain?.managementMode === 'fusion' ? 'bg-blue-600/20 border-blue-500' : 'bg-slate-800 border-slate-600 hover:border-slate-500'}`}
                        onClick={() => !currentDomain?.isSuper && setCurrentDomain(prev => ({ ...prev, managementMode: 'fusion' }))}
                     >
                        <div className={`mt-0.5 rounded-full p-1 ${currentDomain?.managementMode === 'fusion' ? 'bg-blue-500 text-white' : 'bg-slate-700 text-slate-400'}`}>
                             <Users size={14} />
                        </div>
                        <div>
                            <div className="text-sm font-semibold text-slate-200">跨域融合模式</div>
                            <div className="text-xs text-slate-400 mt-1 leading-relaxed">
                                支持跨域查询，管理员可直接访问所有关联客户的数据，适合集中化管理场景。
                            </div>
                        </div>
                     </div>

                     <div 
                        className={`border rounded p-3 cursor-pointer transition-all flex items-start gap-3 ${currentDomain?.managementMode === 'switching' ? 'bg-blue-600/20 border-blue-500' : 'bg-slate-800 border-slate-600 hover:border-slate-500'}`}
                        onClick={() => !currentDomain?.isSuper && setCurrentDomain(prev => ({ ...prev, managementMode: 'switching' }))}
                     >
                        <div className={`mt-0.5 rounded-full p-1 ${currentDomain?.managementMode === 'switching' ? 'bg-blue-500 text-white' : 'bg-slate-700 text-slate-400'}`}>
                             <Repeat size={14} />
                        </div>
                        <div>
                            <div className="text-sm font-semibold text-slate-200">按域切换模式</div>
                            <div className="text-xs text-slate-400 mt-1 leading-relaxed">
                                需切换不同上下文来访问特定数据，数据隔离性强，适合多租户或独立分公司管理。
                            </div>
                        </div>
                     </div>
                </div>
                {currentDomain?.isSuper && <div className="mt-2 text-xs text-yellow-500/80">* 总控中心默认启用跨域融合模式，拥有全局视野。</div>}
           </div>
          </div>

           {/* Customer Transfer Frame */}
           <div className="border-t border-slate-700 pt-4">
               <label className="text-sm font-medium text-slate-300 mb-2 block">
                   关联客户配置
               </label>

               {currentDomain?.isSuper ? (
                   <div className="bg-slate-800/50 rounded-lg p-6 text-center border border-slate-700 border-dashed">
                       <Crown size={32} className="mx-auto text-yellow-500 mb-2 opacity-50"/>
                       <p className="text-slate-300 font-medium">总控中心默认拥有所有客户权限</p>
                       <p className="text-slate-500 text-sm mt-1">无需手动配置关联客户</p>
                   </div>
               ) : (
                <div className="flex h-[320px] gap-4">
                  {/* Left: Source */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg space-y-2">
                         <div className="flex gap-2">
                             <Input 
                                placeholder="搜索客户..." 
                                className="h-8 text-sm py-1" 
                                value={transferSearch}
                                onChange={(e) => { setTransferSearch(e.target.value); setTransferPage(1); }}
                             />
                         </div>
                         <div className="flex justify-between items-center px-1">
                             <label className="flex items-center space-x-2 cursor-pointer text-xs text-slate-300 select-none">
                                <input 
                                    type="checkbox" 
                                    className="rounded bg-slate-900 border-slate-600 text-blue-500" 
                                    onChange={(e) => handleSelectAllSource(e.target.checked)}
                                    checked={filteredSource.length > 0 && filteredSource.every(c => selectedSource.includes(c.id))}
                                />
                                <span>全选 ({filteredSource.length})</span>
                             </label>
                             <span className="text-xs text-slate-500">{selectedSource.length} 已选</span>
                         </div>
                      </div>

                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {currentSourcePage.map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedSource.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedSource.includes(item.id)
                                      ? setSelectedSource(selectedSource.filter(id => id !== item.id))
                                      : setSelectedSource([...selectedSource, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedSource.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                         {filteredSource.length === 0 && <div className="text-center py-4 text-xs text-slate-500">无匹配数据</div>}
                      </div>

                      {/* Pagination Controls */}
                      {totalTransferPages > 1 && (
                          <div className="p-2 border-t border-slate-700 flex justify-between items-center bg-slate-800/30">
                              <button disabled={transferPage === 1} onClick={() => setTransferPage(p => p - 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronLeft size={16}/></button>
                              <span className="text-xs text-slate-400">{transferPage} / {totalTransferPages}</span>
                              <button disabled={transferPage === totalTransferPages} onClick={() => setTransferPage(p => p + 1)} className="p-1 hover:text-white text-slate-400 disabled:opacity-30"><ChevronRight size={16}/></button>
                          </div>
                      )}
                  </div>

                  {/* Actions */}
                  <div className="flex flex-col justify-center gap-3">
                        <Button size="sm" variant="secondary" onClick={moveToTarget} disabled={selectedSource.length === 0} title="添加" className="w-10">
                            <ChevronsRight size={18} />
                        </Button>
                        <Button size="sm" variant="secondary" onClick={moveToSource} disabled={selectedTarget.length === 0} title="移除" className="w-10">
                            <ChevronsLeft size={18} />
                        </Button>
                  </div>

                  {/* Right: Target */}
                  <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                      <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[76px]">
                          <span className="text-xs font-semibold text-slate-300 pl-1">已关联客户 ({currentCustomerIds.length})</span>
                          <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setCurrentDomain(prev => ({...prev, customerIds: []}))}>清空</Button>
                      </div>
                      <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                         {MOCK_CUSTOMERS.filter(c => currentCustomerIds.includes(c.id)).map(item => (
                            <div 
                                key={item.id} 
                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${selectedTarget.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                onClick={() => {
                                    selectedTarget.includes(item.id)
                                      ? setSelectedTarget(selectedTarget.filter(id => id !== item.id))
                                      : setSelectedTarget([...selectedTarget, item.id])
                                }}
                            >
                                <input type="checkbox" checked={selectedTarget.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                <div className="flex flex-col overflow-hidden">
                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                    <span className="text-[10px] text-slate-500">{item.code}</span>
                                </div>
                            </div>
                         ))}
                      </div>
                  </div>
               </div>
               )}
           </div>

           <Input label="备注" />
        </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '启用' : '禁用'}该域吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除域"
         message={`确定要删除“${deleteTarget?.name}”吗？此操作不可恢复。`}
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTarget(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination } from '../components/UI';
import { Plus, Edit2, Trash2, Folder, FileText, MousePointer, Search, RotateCcw } from 'lucide-react';
import { MOCK_MENUS } from '../constants';
import { Menu } from '../types';

const ITEMS_PER_PAGE = 10;

export const MenuManager: React.FC = () => {
  const [data, setData] = useState<Menu[]>(MOCK_MENUS);
  const [currentPage, setCurrentPage] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchKeyword, setSearchKeyword] = useState('');

  // State for the menu being edited/created
  const [currentMenu, setCurrentMenu] = useState<Partial<Menu> & { isExternal?: boolean; isCache?: boolean }>({});

  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newVisible: boolean } | null>(null);

  // Delete Confirm State
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  const flattenMenus = (menus: Menu[], depth = 0): (Menu & { depth: number })[] => {
    let result: (Menu & { depth: number })[] = [];
    menus.forEach(m => {
      result.push({ ...m, depth });
      if (m.children) {
        result = result.concat(flattenMenus(m.children, depth + 1));
      }
    });
    return result;
  };

  const flatData = useMemo(() => {
    const all = flattenMenus(data);
    if (!searchKeyword) return all;
    // Simple filter: if name matches, show. 
    return all.filter(m => m.name.toLowerCase().includes(searchKeyword.toLowerCase()));
  }, [data, searchKeyword]);

  // Pagination
  const totalPages = Math.ceil(flatData.length / ITEMS_PER_PAGE);
  const paginatedData = flatData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Generate Parent Options for Select (using full flattened data)
  const fullFlatData = useMemo(() => flattenMenus(data), [data]);
  const parentOptions = [
      { label: '主目录', value: '0' },
      ...fullFlatData
          // Prevent selecting itself as parent or buttons as parent
          .filter(m => m.id !== currentMenu.id && m.type !== 'button')
          .map(m => ({ label: '　'.repeat(m.depth) + m.name, value: m.id }))
  ];

  const handleEdit = (menu: Menu) => {
    // Populate form with existing data
    setCurrentMenu({ 
        ...menu, 
        parentId: menu.parentId || '0',
        // Mocking extra fields not in interface for UI demo persistence
        isExternal: false, 
        isCache: true 
    });
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    // Reset form for new entry
    setCurrentMenu({ 
        type: 'menu', 
        parentId: '0', 
        sort: 1, 
        visible: true,
        isExternal: false,
        isCache: true
    });
    setIsModalOpen(true);
  };

  const handleSave = () => {
      // Basic Validation
      if (!currentMenu.name || !currentMenu.type) {
          alert("请填写必要信息");
          return;
      }

      const menuToSave = {
          ...currentMenu,
          parentId: currentMenu.parentId === '0' ? null : currentMenu.parentId,
      } as Menu;

      if (currentMenu.id) {
          // UPDATE Logic (Recursive)
          const updateNode = (nodes: Menu[]): Menu[] => {
              return nodes.map(n => {
                  if (n.id === currentMenu.id) {
                      return { ...n, ...menuToSave };
                  }
                  if (n.children) {
                      return { ...n, children: updateNode(n.children) };
                  }
                  return n;
              });
          };
          setData(updateNode(data));
      } else {
          // CREATE Logic
          const newId = Date.now().toString();
          const newMenu = { ...menuToSave, id: newId, children: [] };

          if (newMenu.parentId) {
              // Add to specific parent
              const addNode = (nodes: Menu[]): Menu[] => {
                  return nodes.map(n => {
                      if (n.id === newMenu.parentId) {
                          return { ...n, children: [...(n.children || []), newMenu] };
                      }
                      if (n.children) {
                          return { ...n, children: addNode(n.children) };
                      }
                      return n;
                  });
              };
              setData(addNode(data));
          } else {
              // Add to root
              setData([...data, newMenu]);
          }
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      const target = fullFlatData.find(m => m.id === id);
      if (target && target.children && target.children.length > 0) {
          alert("该菜单包含子菜单，请先删除子菜单！");
          return;
      }
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          const removeNode = (nodes: Menu[]): Menu[] => {
              return nodes.filter(n => n.id !== deleteTargetId).map(n => ({
                  ...n,
                  children: n.children ? removeNode(n.children) : []
              }));
          };
          setData(removeNode(data));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const initiateStatusChange = (menu: Menu, checked: boolean) => {
    setTargetStatusChange({ id: menu.id, newVisible: checked });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
     if (targetStatusChange) {
         const updateVisible = (items: Menu[]): Menu[] => {
             return items.map(item => {
                 if (item.id === targetStatusChange.id) {
                     return { ...item, visible: targetStatusChange.newVisible };
                 }
                 if (item.children) {
                     return { ...item, children: updateVisible(item.children) };
                 }
                 return item;
             });
         };
         setData(updateVisible(data));
     }
     setConfirmOpen(false);
     setTargetStatusChange(null);
  };

  const columns = [
    { 
      header: '菜单名称', 
      accessor: (row: any) => (
        <div style={{ paddingLeft: `${row.depth * 24}px` }} className="flex items-center">
           {row.type === 'dir' && <Folder size={16} className="text-yellow-500 mr-2" />}
           {row.type === 'menu' && <FileText size={16} className="text-blue-400 mr-2" />}
           {row.type === 'button' && <MousePointer size={16} className="text-slate-400 mr-2" />}
           <span className="text-slate-200">{row.name}</span>
        </div>
      ) 
    },
    { header: '路由地址', accessor: (row: Menu) => <span className="text-slate-400 font-mono text-xs">{row.path || '-'}</span> },
    { header: '权限标识', accessor: (row: Menu) => <Badge color="gray">{row.permission || '-'}</Badge> },
    { header: '组件路径', accessor: (row: Menu) => <span className="text-slate-500 text-xs">{row.component || '-'}</span> },
    { header: '排序', accessor: 'sort', width: '80px' },
    { 
      header: '状态', 
      accessor: (row: Menu) => (
        <Switch 
          checked={row.visible} 
          onChange={(checked) => initiateStatusChange(row, checked)} 
        />
      ) 
    },
    {
      header: '操作',
      accessor: (row: Menu) => (
        <div className="flex space-x-2">
          <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row)}>编辑</Button>
          <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.id)}>删除</Button>
        </div>
      )
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
      <Card className="shrink-0">
         <div className="flex justify-between items-center">
            <div className="flex gap-2">
                <Input 
                    placeholder="菜单名称" 
                    className="w-64" 
                    value={searchKeyword}
                    onChange={(e) => { setSearchKeyword(e.target.value); setCurrentPage(1); }}
                />
                <Button icon={<Search size={16} />}>查询</Button>
                <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchKeyword(''); setCurrentPage(1); }}>重置</Button>
            </div>
            <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<Plus size={16} />} onClick={handleAdd}>新增菜单</Button>
         </div>
      </Card>

      <Card className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-auto">
          <Table columns={columns} data={paginatedData} />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatData.length} 条</div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
        </div>
      </Card>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentMenu.id ? "编辑菜单" : "新增菜单"}
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>确定</Button>
            </>
          }
      >
         <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                    <label className="text-sm font-medium text-slate-300 mb-2 block">类型</label>
                    <div className="flex space-x-4">
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="dir"
                                checked={currentMenu.type === 'dir'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'dir'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'dir' ? 'text-blue-400' : 'text-slate-400'}>目录</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="menu"
                                checked={currentMenu.type === 'menu'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'menu'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'menu' ? 'text-blue-400' : 'text-slate-400'}>菜单</span>
                        </label>
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input 
                                type="radio" 
                                name="type" 
                                value="button"
                                checked={currentMenu.type === 'button'}
                                onChange={() => setCurrentMenu({...currentMenu, type: 'button'})}
                                className="text-blue-500 bg-slate-900 border-slate-600" 
                            />
                            <span className={currentMenu.type === 'button' ? 'text-blue-400' : 'text-slate-400'}>按钮/权限</span>
                        </label>
                    </div>
                </div>

                <div className="col-span-2">
                    <Select 
                        label="上级菜单" 
                        options={parentOptions}
                        value={currentMenu.parentId || '0'}
                        onChange={(e) => setCurrentMenu({...currentMenu, parentId: e.target.value})}
                    />
                </div>

                <div className="col-span-1">
                    <Input 
                        label="菜单名称" 
                        value={currentMenu.name || ''}
                        onChange={(e) => setCurrentMenu({...currentMenu, name: e.target.value})}
                        placeholder="请输入名称"
                    />
                </div>

                <div className="col-span-1">
                    <Input 
                        label="权限标识" 
                        value={currentMenu.permission || ''}
                        onChange={(e) => setCurrentMenu({...currentMenu, permission: e.target.value})}
                        placeholder="sys:user:list"
                    />
                </div>

                <div className="col-span-1">
                    <Input 
                        label="路由地址" 
                        value={currentMenu.path || ''}
                        onChange={(e) => setCurrentMenu({...currentMenu, path: e.target.value})}
                        placeholder="e.g. /system/user"
                        disabled={currentMenu.type === 'button'}
                        className={currentMenu.type === 'button' ? 'opacity-50 cursor-not-allowed' : ''}
                    />
                </div>

                <div className="col-span-1">
                    <Input 
                        label="显示排序" 
                        type="number"
                        value={currentMenu.sort || 0}
                        onChange={(e) => setCurrentMenu({...currentMenu, sort: parseInt(e.target.value)})}
                    />
                </div>

                <div className="col-span-1">
                    <Input 
                        label="组件路径" 
                        value={currentMenu.component || ''}
                        onChange={(e) => setCurrentMenu({...currentMenu, component: e.target.value})}
                        placeholder="e.g. system/User"
                        disabled={currentMenu.type !== 'menu'}
                        className={currentMenu.type !== 'menu' ? 'opacity-50 cursor-not-allowed' : ''}
                    />
                </div>

                <div className="col-span-1">
                     <label className="text-sm font-medium text-slate-300 mb-2 block">状态</label>
                     <div className="flex items-center space-x-3 h-[38px]">
                        <label className="flex items-center space-x-2">
                            <span className="text-sm text-slate-400">显示</span>
                            <Switch checked={currentMenu.visible ?? true} onChange={(c) => setCurrentMenu({...currentMenu, visible: c})} />
                        </label>
                     </div>
                </div>

            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newVisible ? '显示' : '隐藏'}该菜单吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />
      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除菜单"
         message="确定要删除该菜单及其子菜单吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, ConfirmDialog, Pagination } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, CheckSquare, Square, Shield, ChevronRight, ChevronDown, Folder, UserPlus, Lock, Filter } from 'lucide-react';
import { MOCK_ROLES, REGIONS, MOCK_DOMAINS, MOCK_MENUS, BUSINESS_TYPES } from '../constants';
import { Role, Domain, Menu } from '../types';

// Type to represent either a domain header or a role item row
type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; roleCount: number; expanded: boolean }
  | { type: 'role'; id: string; data: Role; parentDomainId: string };

const ITEMS_PER_PAGE = 8;

export const RoleManager: React.FC = () => {
  const [roleData, setRoleData] = useState<Role[]>(MOCK_ROLES);
  const [currentPage, setCurrentPage] = useState(1);

  // Expanded Domains State (Set of Domain IDs)
  // Default all open for better visibility
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<Partial<Role>>({});

  // Menu Permissions State (IDs)
  const [selectedMenuIds, setSelectedMenuIds] = useState<Set<string>>(new Set());

  const [isDomainLocked, setIsDomainLocked] = useState(false); // New state to control select lock
  const [activeTab, setActiveTab] = useState<'info' | 'menu' | 'data'>('info');

  // Search
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');

  // Delete Confirmation
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // --- Mock Transfer Data State (Local to Modal) ---
  const [sourceData] = useState(() => {
      const list = [];
      for(let i=1; i<=8; i++) list.push({ id: `line-${i}`, name: `互联网专线-电路${i}`, category: 'BIZ_LINE' });
      for(let i=1; i<=8; i++) list.push({ id: `5g-${i}`, name: `5G切片-车间${i}`, category: 'BIZ_5G' });
      for(let i=1; i<=8; i++) list.push({ id: `idc-${i}`, name: `IDC机柜-机房${i}`, category: 'BIZ_IDC' });
      for(let i=1; i<=5; i++) list.push({ id: `comp-${i}`, name: `东数西算-节点${i}`, category: 'BIZ_COMP' });
      return list;
  });

  const [targetKeys, setTargetKeys] = useState<string[]>([]); 
  const [sourceSelected, setSourceSelected] = useState<string[]>([]);
  const [targetSelected, setTargetSelected] = useState<string[]>([]);

  // Business Category Filter State
  const [bizCategoryFilter, setBizCategoryFilter] = useState<string>('all');

  useEffect(() => {
    if (isModalOpen) {
        setTargetKeys([]); 
        setSourceSelected([]);
        setTargetSelected([]);
        setBizCategoryFilter('all');
        setSelectedMenuIds(new Set(['1', '11']));
    }
  }, [isModalOpen]);

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  // --- Process Data into Flat Tree Structure ---
  const flatTreeData = useMemo(() => {
    let filteredRoles = roleData;
    if (searchName) filteredRoles = filteredRoles.filter(r => r.name.includes(searchName));
    if (searchCode) filteredRoles = filteredRoles.filter(r => r.code.includes(searchCode));

    const result: TreeItem[] = [];
    MOCK_DOMAINS.forEach(domain => {
        const domainRoles = filteredRoles.filter(r => r.domainId === domain.id);
        if ((searchName || searchCode) && domainRoles.length === 0) return; 

        const isExpanded = expandedDomains.has(domain.id);
        result.push({
            type: 'domain',
            id: `d-${domain.id}`,
            data: domain,
            roleCount: domainRoles.length,
            expanded: isExpanded
        });

        if (isExpanded) {
            domainRoles.forEach(role => {
                result.push({
                    type: 'role',
                    id: role.id,
                    data: role,
                    parentDomainId: domain.id
                });
            });
        }
    });

    return result;
  }, [roleData, expandedDomains, searchName, searchCode]);

  // Pagination
  const totalPages = Math.ceil(flatTreeData.length / ITEMS_PER_PAGE);
  const paginatedData = flatTreeData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // --- Handlers ---
  const moveToRight = () => {
    setTargetKeys([...targetKeys, ...sourceSelected]);
    setSourceSelected([]);
  };
  const moveToLeft = () => {
    setTargetKeys(targetKeys.filter(k => !targetSelected.includes(k)));
    setTargetSelected([]);
  };

  const handleEdit = (role: Role) => {
    setCurrentRole({ ...role });
    setIsDomainLocked(true); // Always lock domain on edit
    setActiveTab('info');
    setIsModalOpen(true);
  };

  // Triggered by Top Button
  const handleGlobalAdd = () => {
    setCurrentRole({ 
        domainId: MOCK_DOMAINS[0]?.id || '', // Default to first
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setIsDomainLocked(false);
    setActiveTab('info');
    setIsModalOpen(true);
  };

  // Triggered by Domain Row Button
  const handleAddInDomain = (domainId: string) => {
    setCurrentRole({ 
        domainId: domainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setIsDomainLocked(true); // Locked to this domain
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteId(id);
      setConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteId) {
          setRoleData(roleData.filter(r => r.id !== deleteId));
      }
      setConfirmOpen(false);
      setDeleteId(null);
  };

  const handleSave = () => {
      if (currentRole.id) {
          setRoleData(roleData.map(r => r.id === currentRole.id ? { ...r, ...currentRole } as Role : r));
      } else {
          const newRole = { 
              ...currentRole, 
              id: Date.now().toString(),
              code: currentRole.code || `ROLE_${Date.now()}` 
          } as Role;
          setRoleData([...roleData, newRole]);
      }
      setIsModalOpen(false);
  };

  // --- Menu Permissions Logic ---
  const getChildIds = (menu: Menu): string[] => {
      let ids: string[] = [];
      if (menu.children) {
          menu.children.forEach(child => {
              ids.push(child.id);
              ids = [...ids, ...getChildIds(child)];
          });
      }
      return ids;
  };

  const getParentIds = (targetId: string, menus: Menu[], path: string[] = []): string[] => {
      for (const menu of menus) {
          if (menu.id === targetId) return path;
          if (menu.children) {
              const res = getParentIds(targetId, menu.children, [...path, menu.id]);
              if (res.length > 0) return res;
          }
      }
      return [];
  };

  const toggleMenu = (menu: Menu, checked: boolean) => {
      const newSelected = new Set(selectedMenuIds);
      const childIds = getChildIds(menu);

      if (checked) {
          newSelected.add(menu.id);
          childIds.forEach(id => newSelected.add(id));
          const parentIds = getParentIds(menu.id, MOCK_MENUS);
          parentIds.forEach(id => newSelected.add(id));
      } else {
          newSelected.delete(menu.id);
          childIds.forEach(id => newSelected.delete(id));
      }
      setSelectedMenuIds(newSelected);
  };

  const renderMenuTree = (menus: Menu[], depth = 0) => {
      return menus.map(menu => {
          const isChecked = selectedMenuIds.has(menu.id);
          return (
              <div key={menu.id}>
                  <div 
                      className={`flex items-center space-x-2 py-1.5 cursor-pointer hover:bg-slate-800 rounded px-2 transition-colors`}
                      style={{ paddingLeft: `${depth * 20 + 8}px` }}
                      onClick={() => toggleMenu(menu, !isChecked)}
                  >
                      {isChecked 
                          ? <CheckSquare size={16} className="text-blue-500 shrink-0" /> 
                          : <Square size={16} className="text-slate-500 shrink-0" />
                      }
                      <span className={`${isChecked ? 'text-white' : 'text-slate-400'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderMenuTree(menu.children, depth + 1)}
              </div>
          );
      });
  };

  const isAllRegionsSelected = (currentRole.regionScope?.length || 0) === REGIONS.length;

  const toggleAllRegions = () => {
      if (isAllRegionsSelected) {
          setCurrentRole({ ...currentRole, regionScope: [] });
      } else {
          setCurrentRole({ ...currentRole, regionScope: REGIONS.map(r => r.code) });
      }
  };

  const toggleRegion = (code: string) => {
      const current = currentRole.regionScope || [];
      if (current.includes(code)) {
          setCurrentRole({ ...currentRole, regionScope: current.filter(c => c !== code) });
      } else {
          setCurrentRole({ ...currentRole, regionScope: [...current, code] });
      }
  };

  const filteredSourceData = useMemo(() => {
      let res = sourceData.filter(d => !targetKeys.includes(d.id));
      if (bizCategoryFilter !== 'all') {
          res = res.filter(d => d.category === bizCategoryFilter);
      }
      return res;
  }, [sourceData, targetKeys, bizCategoryFilter]);


  // --- Render Table Columns ---
  const columns = [
    { 
      header: '名称 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-blue-500 fill-blue-500/10 group-hover:text-blue-400" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.roleCount} 角色</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10 text-slate-300 relative">
                       {/* Tree connector lines visual trick */}
                      <div className="absolute left-[29px] top-[-20px] bottom-[50%] w-[1px] bg-slate-700"></div>
                      <div className="absolute left-[29px] top-[50%] w-4 h-[1px] bg-slate-700"></div>

                      <Shield size={16} className="mr-2 text-green-500" />
                      <span className="font-medium hover:text-green-400 transition-colors cursor-default">{row.data.name}</span>
                  </div>
              );
          }
      },
      width: '35%'
    },
    { 
      header: '编码', 
      accessor: (row: TreeItem) => row.type === 'role' ? <Badge color="gray">{row.data.code}</Badge> : <span className="text-slate-600 text-xs italic opacity-50">{row.data.code}</span>,
      width: '20%'
    },
    { 
      header: '描述', 
      accessor: (row: TreeItem) => row.type === 'role' ? <span className="text-slate-400 text-sm truncate block max-w-xs">{row.data.description}</span> : '',
    },
    {
      header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAddInDomain(row.data.id)}>
                    新增角色
                </Button>
              )
          }
          return (
            <div className="flex space-x-2">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>配置</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '200px'
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
      {/* Search Bar */}
      <Card className="shrink-0">
         <div className="flex justify-between items-center">
            <div className="flex gap-4">
                <Input placeholder="搜索角色名称" className="w-48" value={searchName} onChange={e => { setSearchName(e.target.value); setCurrentPage(1); }} />
                <Input placeholder="搜索角色编码" className="w-48" value={searchCode} onChange={e => { setSearchCode(e.target.value); setCurrentPage(1); }} />
                <div className="flex gap-2 pb-0.5">
                    <Button icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchCode(''); setCurrentPage(1); }}>重置</Button>
                </div>
            </div>
            <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<UserPlus size={16} />} onClick={handleGlobalAdd}>新增角色</Button>
         </div>
      </Card>

      {/* Role Tree Table */}
      <Card className="flex-1 overflow-hidden flex flex-col" title="角色权限树">
        <div className="flex-1 overflow-auto">
          <Table columns={columns} data={paginatedData} keyField="id" />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
        </div>
      </Card>

      {/* Add/Edit Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentRole.id ? "配置角色权限" : "新增角色"}
        size="lg"
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>保存配置</Button>
            </>
          }
      >
         {/* ... (Existing Modal Content) ... */}
         <div className="h-[550px] flex flex-col">
            {/* Tabs */}
            <div className="flex border-b border-slate-700 mb-4 shrink-0">
                {(['info', 'menu', 'data'] as const).map(tab => (
                    <button 
                        key={tab}
                        onClick={() => setActiveTab(tab)}
                        className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-400 hover:text-slate-200'}`}
                    >
                        {tab === 'info' && '基本信息'}
                        {tab === 'menu' && '菜单权限'}
                        {tab === 'data' && '数据权限'}
                    </button>
                ))}
            </div>

            {/* Tab Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1">

                {/* 1. Basic Info */}
                {activeTab === 'info' && (
                    <div className="space-y-4 max-w-lg mx-auto mt-4">
                        <Input 
                            label="角色名称" 
                            value={currentRole.name || ''} 
                            onChange={e => setCurrentRole({...currentRole, name: e.target.value})}
                            placeholder="请输入角色名称" 
                        />
                        <Input 
                            label="角色编码" 
                            value={currentRole.code || ''} 
                            onChange={e => setCurrentRole({...currentRole, code: e.target.value})}
                            placeholder="ROLE_..." 
                            disabled={!!currentRole.id}
                        />
                        <div className="relative">
                            <Select 
                                label="所属域" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentRole.domainId}
                                onChange={e => setCurrentRole({...currentRole, domainId: e.target.value})}
                                disabled={isDomainLocked} // Locked based on context
                                className={isDomainLocked ? "opacity-60 cursor-not-allowed bg-slate-900/50" : ""}
                            />
                            {isDomainLocked && (
                                <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                    <Lock size={12} />
                                    <span className="text-xs">已锁定</span>
                                </div>
                            )}
                        </div>
                        <Input 
                            label="描述" 
                            value={currentRole.description || ''}
                            onChange={e => setCurrentRole({...currentRole, description: e.target.value})}
                        />
                    </div>
                )}

                {/* 2. Menu Permissions */}
                {activeTab === 'menu' && (
                    <div className="space-y-4">
                        <div className="bg-blue-900/10 border border-blue-900/30 rounded p-3 text-xs text-blue-300 mb-2">
                            提示：勾选该角色可访问的菜单资源。父级菜单被选中时，子级菜单默认选中；子级选中时，父级自动选中。
                        </div>
                        {/* Recursive Tree */}
                        <div className="border border-slate-700 rounded p-4 bg-slate-900/50 min-h-[300px]">
                            {renderMenuTree(MOCK_MENUS)}
                        </div>
                    </div>
                )}

                {/* 3. Data Permissions */}
                {activeTab === 'data' && (
                    <div className="space-y-6">
                        {/* Region Scope */}
                        <div className="bg-slate-800/30 p-4 rounded-lg border border-slate-700">
                            <div className="flex justify-between items-center mb-3">
                                <h4 className="text-sm font-bold text-slate-200 flex items-center">
                                    <span className="w-1 h-4 bg-blue-500 rounded mr-2"></span>
                                    区域范围 (Region Scope)
                                </h4>
                                <label className="flex items-center space-x-2 cursor-pointer text-xs text-blue-400 hover:text-blue-300 select-none">
                                    <input 
                                        type="checkbox" 
                                        className="rounded bg-slate-900 border-slate-600 text-blue-500"
                                        checked={isAllRegionsSelected}
                                        onChange={toggleAllRegions}
                                    />
                                    <span>全选区域</span>
                                </label>
                            </div>
                            <div className="grid grid-cols-4 gap-3">
                                {REGIONS.slice(0, 16).map(reg => (
                                    <label key={reg.code} className="flex items-center space-x-2 cursor-pointer hover:text-blue-400 group">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900" 
                                            checked={currentRole.regionScope?.includes(reg.code) || false}
                                            onChange={() => toggleRegion(reg.code)}
                                        />
                                        <span className="text-sm text-slate-400 group-hover:text-slate-200">{reg.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>

                        {/* Business Scope (Transfer) */}
                        <div className="bg-slate-800/30 p-4 rounded-lg border border-slate-700">
                            <h4 className="text-sm font-bold text-slate-200 mb-3 flex items-center">
                                <span className="w-1 h-4 bg-blue-500 rounded mr-2"></span>
                                业务范围 (Business Scope)
                            </h4>

                            <div className="flex h-[300px] gap-4">
                                {/* Source Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex flex-col gap-2">
                                        <div className="flex justify-between items-center">
                                            <span className="text-xs font-semibold text-slate-300">待选业务</span>
                                            <span className="text-xs text-slate-500">{sourceSelected.length} 选中</span>
                                        </div>

                                        {/* Business Category Filter */}
                                        <div className="flex gap-1 overflow-x-auto pb-1 no-scrollbar">
                                            <button 
                                                onClick={() => setBizCategoryFilter('all')}
                                                className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === 'all' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                            >
                                                全部
                                            </button>
                                            {BUSINESS_TYPES.map(bt => (
                                                <button 
                                                    key={bt.code}
                                                    onClick={() => setBizCategoryFilter(bt.code)}
                                                    className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === bt.code ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                                >
                                                    {bt.name}
                                                </button>
                                            ))}
                                        </div>

                                        <Input placeholder="搜索业务实例..." className="text-xs py-1 h-8" />
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {filteredSourceData.map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${sourceSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    sourceSelected.includes(item.id) 
                                                      ? setSourceSelected(sourceSelected.filter(id => id !== item.id))
                                                      : setSourceSelected([...sourceSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={sourceSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                        {filteredSourceData.length === 0 && (
                                            <div className="text-center py-4 text-xs text-slate-500">无匹配数据</div>
                                        )}
                                    </div>
                                </div>

                                {/* Actions */}
                                <div className="flex flex-col justify-center gap-3">
                                    <Button size="sm" variant="secondary" onClick={moveToRight} disabled={sourceSelected.length === 0} title="添加选中">
                                        <ChevronRight size={16} />
                                    </Button>
                                    <Button size="sm" variant="secondary" onClick={moveToLeft} disabled={targetSelected.length === 0} title="移除选中" className="rotate-180">
                                        <ChevronRight size={16} />
                                    </Button>
                                </div>

                                {/* Target Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[90px]">
                                        <span className="text-xs font-semibold text-slate-300">已授权业务 ({targetKeys.length})</span>
                                        <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setTargetKeys([])}>清空</Button>
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {sourceData.filter(d => targetKeys.includes(d.id)).map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${targetSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    targetSelected.includes(item.id) 
                                                      ? setTargetSelected(targetSelected.filter(id => id !== item.id))
                                                      : setTargetSelected([...targetSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={targetSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         title="删除角色"
         message="确定要删除该角色吗？此操作不可恢复，且可能导致关联用户失去权限。"
         onConfirm={confirmDelete}
         onCancel={() => { setConfirmOpen(false); setDeleteId(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, UserPlus, Folder, ChevronDown, ChevronRight, User as UserIcon, Mail, Phone, Shield, Lock } from 'lucide-react';
import { MOCK_USERS, MOCK_ROLES, MOCK_DOMAINS } from '../constants';
import { User, Domain, Role } from '../types';

const ITEMS_PER_PAGE = 8;

type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; userCount: number; expanded: boolean }
  | { type: 'user'; id: string; data: User; parentDomainName: string };

export const UserManager: React.FC = () => {
  const [userData, setUserData] = useState<User[]>(MOCK_USERS);
  const [currentPage, setCurrentPage] = useState(1);
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  // Search State
  const [searchKeyword, setSearchKeyword] = useState('');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Partial<User>>({});
  const [selectedRoleIds, setSelectedRoleIds] = useState<Set<string>>(new Set());

  // Confirm Dialogs
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // --- Tree Data Construction ---
  const flatTreeData = useMemo(() => {
      // 1. Filter Users
      const lowerSearch = searchKeyword.toLowerCase();
      const filteredUsers = userData.filter(u => 
          u.username.toLowerCase().includes(lowerSearch) || 
          u.realName.toLowerCase().includes(lowerSearch) ||
          u.phone.includes(lowerSearch)
      );

      const result: TreeItem[] = [];

      MOCK_DOMAINS.forEach(domain => {
          // Find users for this domain
          const domainUsers = filteredUsers.filter(u => u.baseDomainId === domain.id);

          // Determine if domain matches search directly
          const isDomainMatch = domain.name.toLowerCase().includes(lowerSearch);

          // If searching, show if Domain Matches OR if it has matching users
          if (searchKeyword && !isDomainMatch && domainUsers.length === 0) {
              return;
          }

          const isExpanded = expandedDomains.has(domain.id) || !!searchKeyword; // Auto expand on search

          // Add Domain Node
          result.push({
              type: 'domain',
              id: `d-${domain.id}`,
              data: domain,
              userCount: userData.filter(u => u.baseDomainId === domain.id).length, // Show total count, not just filtered
              expanded: isExpanded
          });

          // Add User Nodes
          if (isExpanded) {
              domainUsers.forEach(user => {
                  result.push({
                      type: 'user',
                      id: user.id,
                      data: user,
                      parentDomainName: domain.name
                  });
              });
          }
      });

      return result;
  }, [userData, expandedDomains, searchKeyword]);

  // Pagination
  const totalPages = Math.ceil(flatTreeData.length / ITEMS_PER_PAGE);
  const paginatedData = flatTreeData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // --- Handlers ---

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  const handleEdit = (user: User) => {
      setCurrentUser({ ...user });
      // Extract role IDs that belong to this domain (ignoring cross-domain for now as per requirement)
      const roleIds = user.roles
        .filter(r => r.targetDomainId === user.baseDomainId) // Strict domain check
        .map(r => r.roleId);
      setSelectedRoleIds(new Set(roleIds));
      setIsModalOpen(true);
  };

  const handleAdd = (domainId: string) => {
      setCurrentUser({ 
          status: 'active', 
          baseDomainId: domainId
      });
      setSelectedRoleIds(new Set());
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentUser.username || !currentUser.realName || !currentUser.baseDomainId) {
          alert("请完善基本信息");
          return;
      }

      // Construct Roles: All selected roles are assigned to the baseDomainId
      const newRoles = Array.from(selectedRoleIds).map(rId => {
          const roleDef = MOCK_ROLES.find(r => r.id === rId);
          return {
              roleId: rId,
              targetDomainId: currentUser.baseDomainId!,
              roleName: roleDef?.name
          };
      });

      if (currentUser.id) {
          // Update
          setUserData(userData.map(u => u.id === currentUser.id ? { ...u, ...currentUser, roles: newRoles } as User : u));
      } else {
          // Create
          const newUser = {
              ...currentUser,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              roles: newRoles
          } as User;
          setUserData([...userData, newUser]);
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setUserData(userData.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setUserData(userData.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  // --- Helpers for Modal ---
  // Get available roles for the selected domain
  const availableRoles = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return MOCK_ROLES.filter(r => r.domainId === currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  const toggleRoleSelection = (roleId: string) => {
      const newSet = new Set(selectedRoleIds);
      if (newSet.has(roleId)) newSet.delete(roleId);
      else newSet.add(roleId);
      setSelectedRoleIds(newSet);
  };


  // --- Columns ---
  const columns = [
    { 
      header: '用户 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-yellow-500 fill-yellow-500/10" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.userCount} 用户</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10">
                       {/* Tree visual lines */}
                      <div className="absolute left-[29px] w-[1px] h-full bg-transparent border-l border-slate-700/50 -top-4 bottom-0"></div>
                      <div className="relative flex items-center">
                          <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center mr-3 border border-slate-600 text-slate-300">
                              <UserIcon size={16} />
                          </div>
                          <div>
                              <div className="text-slate-200 font-medium text-sm">{row.data.realName}</div>
                              <div className="text-slate-500 text-xs">{row.data.username}</div>
                          </div>
                      </div>
                  </div>
              );
          }
      },
      width: '30%'
    },
    { 
        header: '联系方式', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            return (
                <div className="flex flex-col text-xs text-slate-400 space-y-1">
                    <div className="flex items-center"><Phone size={12} className="mr-1 opacity-70"/> {row.data.phone}</div>
                    <div className="flex items-center"><Mail size={12} className="mr-1 opacity-70"/> {row.data.email}</div>
                </div>
            )
        }
    },
    { 
        header: '关联角色 (本域)', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            // Filter roles strictly for this domain context
            const roles = row.data.roles.filter(r => r.targetDomainId === row.data.baseDomainId);
            if (roles.length === 0) return <span className="text-slate-600 text-xs italic">未分配角色</span>;

            return (
                <div className="flex gap-1 flex-wrap">
                    {roles.map((r, i) => (
                        <Badge key={i} color="blue" className="flex items-center gap-1">
                            <Shield size={10} />
                            {MOCK_ROLES.find(role => role.id === r.roleId)?.name || r.roleName || '未知角色'}
                        </Badge>
                    ))}
                </div>
            )
        } 
    },
    { 
        header: '状态', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            return (
                <Switch 
                    checked={row.data.status === 'active'} 
                    onChange={(checked) => initiateStatusChange(row.data, checked)} 
                />
            )
        },
        width: '100px'
    },
    {
      header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAdd(row.data.id)}>
                    新增用户
                </Button>
              )
          }
          return (
            <div className="flex space-x-2">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>编辑</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '180px'
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
        {/* Header Actions */}
        <Card className="shrink-0">
            <div className="flex justify-between items-center">
                <div className="flex gap-4 items-center">
                    <Input 
                        placeholder="搜索姓名/账号/手机号..." 
                        className="w-64" 
                        value={searchKeyword} 
                        onChange={e => { setSearchKeyword(e.target.value); setCurrentPage(1); }}
                        prefix={<Search size={16}/>}
                    />
                    <div className="flex gap-2">
                        <Button icon={<Search size={16} />}>查询</Button>
                        <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchKeyword(''); setCurrentPage(1); }}>重置</Button>
                    </div>
                </div>
                {/* Global Add Button Removed to enforce adding via Domain Context */}
            </div>
        </Card>

        {/* Tree Table */}
        <Card className="flex-1 overflow-hidden flex flex-col" title="用户列表 (按域分组)">
            <div className="flex-1 overflow-auto">
                <Table columns={columns} data={paginatedData} keyField="id" />
            </div>
             <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
                <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
             </div>
        </Card>

        {/* Add/Edit Modal */}
        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title={currentUser.id ? "编辑用户" : "新增用户"}
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={handleSave}>确定</Button>
                </>
              }
        >
            <div className="space-y-6">
                {/* 1. Basic Info */}
                <div>
                    <h4 className="text-sm font-bold text-slate-200 mb-3 border-l-2 border-blue-500 pl-2">基本信息</h4>
                    <div className="grid grid-cols-2 gap-4">
                        <Input 
                            label="用户名" 
                            placeholder="登录账号" 
                            value={currentUser.username || ''}
                            onChange={e => setCurrentUser({...currentUser, username: e.target.value})}
                        />
                        <Input 
                            label="真实姓名" 
                            placeholder="员工姓名" 
                            value={currentUser.realName || ''}
                            onChange={e => setCurrentUser({...currentUser, realName: e.target.value})}
                        />
                        <Input 
                            label="手机号" 
                            placeholder="11位手机号" 
                            value={currentUser.phone || ''}
                            onChange={e => setCurrentUser({...currentUser, phone: e.target.value})}
                        />
                        <Input 
                            label="邮箱" 
                            placeholder="Email" 
                            value={currentUser.email || ''}
                            onChange={e => setCurrentUser({...currentUser, email: e.target.value})}
                        />
                        <div className="col-span-2 relative">
                             <Select 
                                label="归属域 (部门/项目组)" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentUser.baseDomainId}
                                disabled={true}
                                className="opacity-60 cursor-not-allowed bg-slate-900/50"
                             />
                             <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                <Lock size={12} />
                                <span className="text-xs">已锁定</span>
                             </div>
                             <p className="text-xs text-slate-500 mt-1">用户的归属域由创建时的上下文决定，不可变更。</p>
                        </div>
                         <div className="col-span-2">
                            <label className="text-sm font-medium text-slate-300 mb-1 block">账户状态</label>
                            <div className="flex items-center gap-3">
                                <span className="text-sm text-slate-400">正常</span>
                                <Switch 
                                    checked={currentUser.status === 'active'}
                                    onChange={c => setCurrentUser({...currentUser, status: c ? 'active' : 'locked'})}
                                />
                                <span className="text-sm text-slate-400">锁定</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* 2. Role Config */}
                <div>
                    <h4 className="text-sm font-bold text-slate-200 mb-3 border-l-2 border-green-500 pl-2 flex justify-between">
                        <span>角色分配</span>
                        <span className="text-xs font-normal text-slate-500 self-end">仅显示归属域 [{MOCK_DOMAINS.find(d => d.id === currentUser.baseDomainId)?.name}] 下的可用角色</span>
                    </h4>

                    <div className="bg-slate-900/50 rounded border border-slate-700 p-4 min-h-[100px]">
                        {availableRoles.length > 0 ? (
                            <div className="grid grid-cols-2 gap-3">
                                {availableRoles.map(role => (
                                    <label key={role.id} className="flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer border border-transparent hover:border-slate-600 transition-colors">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900 mr-3 h-4 w-4"
                                            checked={selectedRoleIds.has(role.id)}
                                            onChange={() => toggleRoleSelection(role.id)}
                                        />
                                        <div>
                                            <div className="text-sm text-slate-200 font-medium">{role.name}</div>
                                            <div className="text-xs text-slate-500">{role.code}</div>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-500 py-4">
                                <Shield size={24} className="mb-2 opacity-50"/>
                                <span className="text-sm">该域下暂无可用角色，请先在角色管理中配置。</span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </Modal>

        <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '解锁' : '锁定'}该用户吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除用户"
         message="确定要删除该用户吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, ConfirmDialog, Pagination } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, CheckSquare, Square, Shield, ChevronRight, ChevronDown, Folder, UserPlus, Lock, Filter } from 'lucide-react';
import { MOCK_ROLES, REGIONS, MOCK_DOMAINS, MOCK_MENUS, BUSINESS_TYPES } from '../constants';
import { Role, Domain, Menu } from '../types';

// Type to represent either a domain header or a role item row
type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; roleCount: number; expanded: boolean }
  | { type: 'role'; id: string; data: Role; parentDomainId: string };

const ITEMS_PER_PAGE = 8;

export const RoleManager: React.FC = () => {
  const [roleData, setRoleData] = useState<Role[]>(MOCK_ROLES);
  const [currentPage, setCurrentPage] = useState(1);

  // Expanded Domains State (Set of Domain IDs)
  // Default all open for better visibility
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentRole, setCurrentRole] = useState<Partial<Role>>({});

  // Menu Permissions State (IDs)
  const [selectedMenuIds, setSelectedMenuIds] = useState<Set<string>>(new Set());

  const [isDomainLocked, setIsDomainLocked] = useState(false); // New state to control select lock
  const [activeTab, setActiveTab] = useState<'info' | 'menu' | 'data'>('info');

  // Search
  const [searchName, setSearchName] = useState('');
  const [searchCode, setSearchCode] = useState('');
  const [searchDomainId, setSearchDomainId] = useState('');

  // Delete Confirmation
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  // --- Mock Transfer Data State (Local to Modal) ---
  const [sourceData] = useState(() => {
      const list = [];
      for(let i=1; i<=8; i++) list.push({ id: `line-${i}`, name: `互联网专线-电路${i}`, category: 'BIZ_LINE' });
      for(let i=1; i<=8; i++) list.push({ id: `5g-${i}`, name: `5G切片-车间${i}`, category: 'BIZ_5G' });
      for(let i=1; i<=8; i++) list.push({ id: `idc-${i}`, name: `IDC机柜-机房${i}`, category: 'BIZ_IDC' });
      for(let i=1; i<=5; i++) list.push({ id: `comp-${i}`, name: `东数西算-节点${i}`, category: 'BIZ_COMP' });
      return list;
  });

  const [targetKeys, setTargetKeys] = useState<string[]>([]); 
  const [sourceSelected, setSourceSelected] = useState<string[]>([]);
  const [targetSelected, setTargetSelected] = useState<string[]>([]);

  // Business Category Filter State
  const [bizCategoryFilter, setBizCategoryFilter] = useState<string>('all');

  useEffect(() => {
    if (isModalOpen) {
        setTargetKeys([]); 
        setSourceSelected([]);
        setTargetSelected([]);
        setBizCategoryFilter('all');
        setSelectedMenuIds(new Set(['1', '11']));
    }
  }, [isModalOpen]);

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  // --- Process Data into Flat Tree Structure ---
  const flatTreeData = useMemo(() => {
    let filteredRoles = roleData;
    if (searchName) filteredRoles = filteredRoles.filter(r => r.name.includes(searchName));
    if (searchCode) filteredRoles = filteredRoles.filter(r => r.code.includes(searchCode));

    const result: TreeItem[] = [];
    MOCK_DOMAINS.forEach(domain => {
        // Filter by Domain ID if selected
        if (searchDomainId && domain.id !== searchDomainId) return;

        const domainRoles = filteredRoles.filter(r => r.domainId === domain.id);

        // If searching by name/code and no roles match, skip this domain
        if ((searchName || searchCode) && domainRoles.length === 0) return; 

        // Auto expand if searching or filtering
        const isExpanded = expandedDomains.has(domain.id) || !!searchName || !!searchCode || !!searchDomainId;

        result.push({
            type: 'domain',
            id: `d-${domain.id}`,
            data: domain,
            roleCount: domainRoles.length,
            expanded: isExpanded
        });

        if (isExpanded) {
            domainRoles.forEach(role => {
                result.push({
                    type: 'role',
                    id: role.id,
                    data: role,
                    parentDomainId: domain.id
                });
            });
        }
    });

    return result;
  }, [roleData, expandedDomains, searchName, searchCode, searchDomainId]);

  // Pagination
  const totalPages = Math.ceil(flatTreeData.length / ITEMS_PER_PAGE);
  const paginatedData = flatTreeData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // --- Handlers ---
  const moveToRight = () => {
    setTargetKeys([...targetKeys, ...sourceSelected]);
    setSourceSelected([]);
  };
  const moveToLeft = () => {
    setTargetKeys(targetKeys.filter(k => !targetSelected.includes(k)));
    setTargetSelected([]);
  };

  const handleEdit = (role: Role) => {
    setCurrentRole({ ...role });
    setIsDomainLocked(true); // Always lock domain on edit
    setActiveTab('info');
    setIsModalOpen(true);
  };

  // Triggered by Top Button
  const handleGlobalAdd = () => {
    setCurrentRole({ 
        domainId: MOCK_DOMAINS[0]?.id || '', // Default to first
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setIsDomainLocked(false);
    setActiveTab('info');
    setIsModalOpen(true);
  };

  // Triggered by Domain Row Button
  const handleAddInDomain = (domainId: string) => {
    setCurrentRole({ 
        domainId: domainId, 
        regionScope: [], 
        bizCategoryScope: [] 
    });
    setIsDomainLocked(true); // Locked to this domain
    setActiveTab('info');
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
      setDeleteId(id);
      setConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteId) {
          setRoleData(roleData.filter(r => r.id !== deleteId));
      }
      setConfirmOpen(false);
      setDeleteId(null);
  };

  const handleSave = () => {
      if (currentRole.id) {
          setRoleData(roleData.map(r => r.id === currentRole.id ? { ...r, ...currentRole } as Role : r));
      } else {
          const newRole = { 
              ...currentRole, 
              id: Date.now().toString(),
              code: currentRole.code || `ROLE_${Date.now()}` 
          } as Role;
          setRoleData([...roleData, newRole]);
      }
      setIsModalOpen(false);
  };

  // --- Menu Permissions Logic ---
  const getChildIds = (menu: Menu): string[] => {
      let ids: string[] = [];
      if (menu.children) {
          menu.children.forEach(child => {
              ids.push(child.id);
              ids = [...ids, ...getChildIds(child)];
          });
      }
      return ids;
  };

  const getParentIds = (targetId: string, menus: Menu[], path: string[] = []): string[] => {
      for (const menu of menus) {
          if (menu.id === targetId) return path;
          if (menu.children) {
              const res = getParentIds(targetId, menu.children, [...path, menu.id]);
              if (res.length > 0) return res;
          }
      }
      return [];
  };

  const toggleMenu = (menu: Menu, checked: boolean) => {
      const newSelected = new Set(selectedMenuIds);
      const childIds = getChildIds(menu);

      if (checked) {
          newSelected.add(menu.id);
          childIds.forEach(id => newSelected.add(id));
          const parentIds = getParentIds(menu.id, MOCK_MENUS);
          parentIds.forEach(id => newSelected.add(id));
      } else {
          newSelected.delete(menu.id);
          childIds.forEach(id => newSelected.delete(id));
      }
      setSelectedMenuIds(newSelected);
  };

  const renderMenuTree = (menus: Menu[], depth = 0) => {
      return menus.map(menu => {
          const isChecked = selectedMenuIds.has(menu.id);
          return (
              <div key={menu.id}>
                  <div 
                      className={`flex items-center space-x-2 py-1.5 cursor-pointer hover:bg-slate-800 rounded px-2 transition-colors`}
                      style={{ paddingLeft: `${depth * 20 + 8}px` }}
                      onClick={() => toggleMenu(menu, !isChecked)}
                  >
                      {isChecked 
                          ? <CheckSquare size={16} className="text-blue-500 shrink-0" /> 
                          : <Square size={16} className="text-slate-500 shrink-0" />
                      }
                      <span className={`${isChecked ? 'text-white' : 'text-slate-400'} text-sm select-none`}>{menu.name}</span>
                  </div>
                  {menu.children && renderMenuTree(menu.children, depth + 1)}
              </div>
          );
      });
  };

  const isAllRegionsSelected = (currentRole.regionScope?.length || 0) === REGIONS.length;

  const toggleAllRegions = () => {
      if (isAllRegionsSelected) {
          setCurrentRole({ ...currentRole, regionScope: [] });
      } else {
          setCurrentRole({ ...currentRole, regionScope: REGIONS.map(r => r.code) });
      }
  };

  const toggleRegion = (code: string) => {
      const current = currentRole.regionScope || [];
      if (current.includes(code)) {
          setCurrentRole({ ...currentRole, regionScope: current.filter(c => c !== code) });
      } else {
          setCurrentRole({ ...currentRole, regionScope: [...current, code] });
      }
  };

  const filteredSourceData = useMemo(() => {
      let res = sourceData.filter(d => !targetKeys.includes(d.id));
      if (bizCategoryFilter !== 'all') {
          res = res.filter(d => d.category === bizCategoryFilter);
      }
      return res;
  }, [sourceData, targetKeys, bizCategoryFilter]);


  // --- Render Table Columns ---
  const columns = [
    { 
      header: '名称 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-blue-500 fill-blue-500/10 group-hover:text-blue-400" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.roleCount} 角色</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10 text-slate-300 relative">
                       {/* Tree connector lines visual trick */}
                      <div className="absolute left-[29px] top-[-20px] bottom-[50%] w-[1px] bg-slate-700"></div>
                      <div className="absolute left-[29px] top-[50%] w-4 h-[1px] bg-slate-700"></div>

                      <Shield size={16} className="mr-2 text-green-500" />
                      <span className="font-medium hover:text-green-400 transition-colors cursor-default">{row.data.name}</span>
                  </div>
              );
          }
      },
      width: '35%'
    },
    { 
      header: '编码', 
      accessor: (row: TreeItem) => row.type === 'role' ? <Badge color="gray">{row.data.code}</Badge> : <span className="text-slate-600 text-xs italic opacity-50">{row.data.code}</span>,
      width: '20%'
    },
    { 
      header: '描述', 
      accessor: (row: TreeItem) => row.type === 'role' ? <span className="text-slate-400 text-sm truncate block max-w-xs">{row.data.description}</span> : '',
    },
    {
      header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAddInDomain(row.data.id)}>
                    新增角色
                </Button>
              )
          }
          return (
            <div className="flex space-x-2">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>配置</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '200px'
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
      {/* Search Bar */}
      <Card className="shrink-0">
         <div className="flex justify-between items-center">
            <div className="flex gap-4">
                <Input placeholder="搜索角色名称" className="w-48" value={searchName} onChange={e => { setSearchName(e.target.value); setCurrentPage(1); }} />
                <Input placeholder="搜索角色编码" className="w-48" value={searchCode} onChange={e => { setSearchCode(e.target.value); setCurrentPage(1); }} />
                <Select 
                    className="w-40" 
                    options={[{label: '全部域', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                    value={searchDomainId}
                    onChange={e => { setSearchDomainId(e.target.value); setCurrentPage(1); }}
                />
                <div className="flex gap-2 pb-0.5">
                    <Button icon={<Search size={16} />}>查询</Button>
                    <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchName(''); setSearchCode(''); setSearchDomainId(''); setCurrentPage(1); }}>重置</Button>
                </div>
            </div>
            <Button variant="primary" className="bg-green-600 hover:bg-green-500" icon={<UserPlus size={16} />} onClick={handleGlobalAdd}>新增角色</Button>
         </div>
      </Card>

      {/* Role Tree Table */}
      <Card className="flex-1 overflow-hidden flex flex-col" title="角色权限树">
        <div className="flex-1 overflow-auto">
          <Table columns={columns} data={paginatedData} keyField="id" />
        </div>
        <div className="py-2 border-t border-slate-700 flex justify-between items-center">
            <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
            <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
        </div>
      </Card>

      {/* Add/Edit Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={currentRole.id ? "配置角色权限" : "新增角色"}
        size="lg"
        footer={
            <>
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
              <Button onClick={handleSave}>保存配置</Button>
            </>
          }
      >
         {/* ... (Existing Modal Content) ... */}
         <div className="h-[550px] flex flex-col">
            {/* Tabs */}
            <div className="flex border-b border-slate-700 mb-4 shrink-0">
                {(['info', 'menu', 'data'] as const).map(tab => (
                    <button 
                        key={tab}
                        onClick={() => setActiveTab(tab)}
                        className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-400 hover:text-slate-200'}`}
                    >
                        {tab === 'info' && '基本信息'}
                        {tab === 'menu' && '菜单权限'}
                        {tab === 'data' && '数据权限'}
                    </button>
                ))}
            </div>

            {/* Tab Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-1">

                {/* 1. Basic Info */}
                {activeTab === 'info' && (
                    <div className="space-y-4 max-w-lg mx-auto mt-4">
                        <Input 
                            label="角色名称" 
                            value={currentRole.name || ''} 
                            onChange={e => setCurrentRole({...currentRole, name: e.target.value})}
                            placeholder="请输入角色名称" 
                        />
                        <Input 
                            label="角色编码" 
                            value={currentRole.code || ''} 
                            onChange={e => setCurrentRole({...currentRole, code: e.target.value})}
                            placeholder="ROLE_..." 
                            disabled={!!currentRole.id}
                        />
                        <div className="relative">
                            <Select 
                                label="所属域" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentRole.domainId}
                                onChange={e => setCurrentRole({...currentRole, domainId: e.target.value})}
                                disabled={isDomainLocked} // Locked based on context
                                className={isDomainLocked ? "opacity-60 cursor-not-allowed bg-slate-900/50" : ""}
                            />
                            {isDomainLocked && (
                                <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                    <Lock size={12} />
                                    <span className="text-xs">已锁定</span>
                                </div>
                            )}
                        </div>
                        <Input 
                            label="描述" 
                            value={currentRole.description || ''}
                            onChange={e => setCurrentRole({...currentRole, description: e.target.value})}
                        />
                    </div>
                )}

                {/* 2. Menu Permissions */}
                {activeTab === 'menu' && (
                    <div className="space-y-4">
                        <div className="bg-blue-900/10 border border-blue-900/30 rounded p-3 text-xs text-blue-300 mb-2">
                            提示：勾选该角色可访问的菜单资源。父级菜单被选中时，子级菜单默认选中；子级选中时，父级自动选中。
                        </div>
                        {/* Recursive Tree */}
                        <div className="border border-slate-700 rounded p-4 bg-slate-900/50 min-h-[300px]">
                            {renderMenuTree(MOCK_MENUS)}
                        </div>
                    </div>
                )}

                {/* 3. Data Permissions */}
                {activeTab === 'data' && (
                    <div className="space-y-6">
                        {/* Region Scope */}
                        <div className="bg-slate-800/30 p-4 rounded-lg border border-slate-700">
                            <div className="flex justify-between items-center mb-3">
                                <h4 className="text-sm font-bold text-slate-200 flex items-center">
                                    <span className="w-1 h-4 bg-blue-500 rounded mr-2"></span>
                                    区域范围 (Region Scope)
                                </h4>
                                <label className="flex items-center space-x-2 cursor-pointer text-xs text-blue-400 hover:text-blue-300 select-none">
                                    <input 
                                        type="checkbox" 
                                        className="rounded bg-slate-900 border-slate-600 text-blue-500"
                                        checked={isAllRegionsSelected}
                                        onChange={toggleAllRegions}
                                    />
                                    <span>全选区域</span>
                                </label>
                            </div>
                            <div className="grid grid-cols-4 gap-3">
                                {REGIONS.slice(0, 16).map(reg => (
                                    <label key={reg.code} className="flex items-center space-x-2 cursor-pointer hover:text-blue-400 group">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900" 
                                            checked={currentRole.regionScope?.includes(reg.code) || false}
                                            onChange={() => toggleRegion(reg.code)}
                                        />
                                        <span className="text-sm text-slate-400 group-hover:text-slate-200">{reg.name}</span>
                                    </label>
                                ))}
                            </div>
                        </div>

                        {/* Business Scope (Transfer) */}
                        <div className="bg-slate-800/30 p-4 rounded-lg border border-slate-700">
                            <h4 className="text-sm font-bold text-slate-200 mb-3 flex items-center">
                                <span className="w-1 h-4 bg-blue-500 rounded mr-2"></span>
                                业务范围 (Business Scope)
                            </h4>

                            <div className="flex h-[300px] gap-4">
                                {/* Source Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex flex-col gap-2">
                                        <div className="flex justify-between items-center">
                                            <span className="text-xs font-semibold text-slate-300">待选业务</span>
                                            <span className="text-xs text-slate-500">{sourceSelected.length} 选中</span>
                                        </div>

                                        {/* Business Category Filter */}
                                        <div className="flex gap-1 overflow-x-auto pb-1 no-scrollbar">
                                            <button 
                                                onClick={() => setBizCategoryFilter('all')}
                                                className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === 'all' ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                            >
                                                全部
                                            </button>
                                            {BUSINESS_TYPES.map(bt => (
                                                <button 
                                                    key={bt.code}
                                                    onClick={() => setBizCategoryFilter(bt.code)}
                                                    className={`px-2 py-1 text-[10px] rounded whitespace-nowrap transition-colors border ${bizCategoryFilter === bt.code ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-800 border-slate-600 text-slate-400 hover:border-slate-500'}`}
                                                >
                                                    {bt.name}
                                                </button>
                                            ))}
                                        </div>

                                        <Input placeholder="搜索业务实例..." className="text-xs py-1 h-8" />
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {filteredSourceData.map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${sourceSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    sourceSelected.includes(item.id) 
                                                      ? setSourceSelected(sourceSelected.filter(id => id !== item.id))
                                                      : setSourceSelected([...sourceSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={sourceSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                        {filteredSourceData.length === 0 && (
                                            <div className="text-center py-4 text-xs text-slate-500">无匹配数据</div>
                                        )}
                                    </div>
                                </div>

                                {/* Actions */}
                                <div className="flex flex-col justify-center gap-3">
                                    <Button size="sm" variant="secondary" onClick={moveToRight} disabled={sourceSelected.length === 0} title="添加选中">
                                        <ChevronRight size={16} />
                                    </Button>
                                    <Button size="sm" variant="secondary" onClick={moveToLeft} disabled={targetSelected.length === 0} title="移除选中" className="rotate-180">
                                        <ChevronRight size={16} />
                                    </Button>
                                </div>

                                {/* Target Panel */}
                                <div className="flex-1 border border-slate-700 rounded-lg flex flex-col bg-slate-900/50">
                                    <div className="p-2 border-b border-slate-700 bg-slate-800/50 rounded-t-lg flex justify-between items-center h-[90px]">
                                        <span className="text-xs font-semibold text-slate-300">已授权业务 ({targetKeys.length})</span>
                                        <Button size="sm" variant="ghost" className="text-red-400 text-xs px-2 h-6" onClick={() => setTargetKeys([])}>清空</Button>
                                    </div>
                                    <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
                                        {sourceData.filter(d => targetKeys.includes(d.id)).map(item => (
                                            <div 
                                                key={item.id} 
                                                className={`flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer ${targetSelected.includes(item.id) ? 'bg-blue-600/20' : ''}`}
                                                onClick={() => {
                                                    targetSelected.includes(item.id) 
                                                      ? setTargetSelected(targetSelected.filter(id => id !== item.id))
                                                      : setTargetSelected([...targetSelected, item.id])
                                                }}
                                            >
                                                <input type="checkbox" checked={targetSelected.includes(item.id)} readOnly className="mr-2 rounded bg-slate-900 border-slate-600 pointer-events-none" />
                                                <div className="flex flex-col overflow-hidden">
                                                    <span className="text-sm truncate text-slate-300">{item.name}</span>
                                                    <span className="text-[10px] text-slate-500">
                                                        {BUSINESS_TYPES.find(b => b.code === item.category)?.name}
                                                    </span>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

            </div>
         </div>
      </Modal>

      <ConfirmDialog 
         isOpen={confirmOpen} 
         title="删除角色"
         message="确定要删除该角色吗？此操作不可恢复，且可能导致关联用户失去权限。"
         onConfirm={confirmDelete}
         onCancel={() => { setConfirmOpen(false); setDeleteId(null); }}
      />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, Table, Button, Badge, Modal, Input, Select, Switch, ConfirmDialog, Pagination } from '../components/UI';
import { Plus, Edit2, Trash2, Search, RotateCcw, UserPlus, Folder, ChevronDown, ChevronRight, User as UserIcon, Mail, Phone, Shield, Lock } from 'lucide-react';
import { MOCK_USERS, MOCK_ROLES, MOCK_DOMAINS } from '../constants';
import { User, Domain, Role } from '../types';

const ITEMS_PER_PAGE = 8;

type TreeItem = 
  | { type: 'domain'; id: string; data: Domain; userCount: number; expanded: boolean }
  | { type: 'user'; id: string; data: User; parentDomainName: string };

export const UserManager: React.FC = () => {
  const [userData, setUserData] = useState<User[]>(MOCK_USERS);
  const [currentPage, setCurrentPage] = useState(1);
  const [expandedDomains, setExpandedDomains] = useState<Set<string>>(new Set(MOCK_DOMAINS.map(d => d.id)));

  // Search State
  const [searchKeyword, setSearchKeyword] = useState('');
  const [searchDomainId, setSearchDomainId] = useState('');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Partial<User>>({});
  const [selectedRoleIds, setSelectedRoleIds] = useState<Set<string>>(new Set());

  // Confirm Dialogs
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [targetStatusChange, setTargetStatusChange] = useState<{ id: string, newStatus: 'active' | 'locked' } | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = useState(false);
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // --- Tree Data Construction ---
  const flatTreeData = useMemo(() => {
      // 1. Filter Users
      const lowerSearch = searchKeyword.toLowerCase();
      const filteredUsers = userData.filter(u => 
          u.username.toLowerCase().includes(lowerSearch) || 
          u.realName.toLowerCase().includes(lowerSearch) ||
          u.phone.includes(lowerSearch)
      );

      const result: TreeItem[] = [];

      MOCK_DOMAINS.forEach(domain => {
          // Filter by Domain ID if selected
          if (searchDomainId && domain.id !== searchDomainId) return;

          // Find users for this domain
          const domainUsers = filteredUsers.filter(u => u.baseDomainId === domain.id);

          // Determine if domain matches search directly
          const isDomainMatch = domain.name.toLowerCase().includes(lowerSearch);

          // If searching, show if Domain Matches OR if it has matching users
          if (searchKeyword && !isDomainMatch && domainUsers.length === 0) {
              return;
          }

          // Auto expand on search
          const isExpanded = expandedDomains.has(domain.id) || !!searchKeyword || !!searchDomainId; 

          // Add Domain Node
          result.push({
              type: 'domain',
              id: `d-${domain.id}`,
              data: domain,
              userCount: userData.filter(u => u.baseDomainId === domain.id).length, // Show total count, not just filtered
              expanded: isExpanded
          });

          // Add User Nodes
          if (isExpanded) {
              domainUsers.forEach(user => {
                  result.push({
                      type: 'user',
                      id: user.id,
                      data: user,
                      parentDomainName: domain.name
                  });
              });
          }
      });

      return result;
  }, [userData, expandedDomains, searchKeyword, searchDomainId]);

  // Pagination
  const totalPages = Math.ceil(flatTreeData.length / ITEMS_PER_PAGE);
  const paginatedData = flatTreeData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // --- Handlers ---

  const toggleDomain = (domainId: string) => {
      const newSet = new Set(expandedDomains);
      if (newSet.has(domainId)) {
          newSet.delete(domainId);
      } else {
          newSet.add(domainId);
      }
      setExpandedDomains(newSet);
  };

  const handleEdit = (user: User) => {
      setCurrentUser({ ...user });
      // Extract role IDs that belong to this domain (ignoring cross-domain for now as per requirement)
      const roleIds = user.roles
        .filter(r => r.targetDomainId === user.baseDomainId) // Strict domain check
        .map(r => r.roleId);
      setSelectedRoleIds(new Set(roleIds));
      setIsModalOpen(true);
  };

  const handleAdd = (domainId: string) => {
      setCurrentUser({ 
          status: 'active', 
          baseDomainId: domainId
      });
      setSelectedRoleIds(new Set());
      setIsModalOpen(true);
  };

  const handleSave = () => {
      if (!currentUser.username || !currentUser.realName || !currentUser.baseDomainId) {
          alert("请完善基本信息");
          return;
      }

      // Construct Roles: All selected roles are assigned to the baseDomainId
      const newRoles = Array.from(selectedRoleIds).map(rId => {
          const roleDef = MOCK_ROLES.find(r => r.id === rId);
          return {
              roleId: rId,
              targetDomainId: currentUser.baseDomainId!,
              roleName: roleDef?.name
          };
      });

      if (currentUser.id) {
          // Update
          setUserData(userData.map(u => u.id === currentUser.id ? { ...u, ...currentUser, roles: newRoles } as User : u));
      } else {
          // Create
          const newUser = {
              ...currentUser,
              id: Date.now().toString(),
              createTime: new Date().toLocaleDateString(),
              roles: newRoles
          } as User;
          setUserData([...userData, newUser]);
      }
      setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
      setDeleteTargetId(id);
      setDeleteConfirmOpen(true);
  };

  const confirmDelete = () => {
      if (deleteTargetId) {
          setUserData(userData.filter(u => u.id !== deleteTargetId));
      }
      setDeleteConfirmOpen(false);
      setDeleteTargetId(null);
  };

  const initiateStatusChange = (user: User, checked: boolean) => {
    setTargetStatusChange({
        id: user.id,
        newStatus: checked ? 'active' : 'locked'
    });
    setConfirmOpen(true);
  };

  const confirmStatusChange = () => {
    if (targetStatusChange) {
        setUserData(userData.map(u => u.id === targetStatusChange.id ? { ...u, status: targetStatusChange.newStatus } : u));
    }
    setConfirmOpen(false);
    setTargetStatusChange(null);
  };

  // --- Helpers for Modal ---
  // Get available roles for the selected domain
  const availableRoles = useMemo(() => {
      if (!currentUser.baseDomainId) return [];
      return MOCK_ROLES.filter(r => r.domainId === currentUser.baseDomainId);
  }, [currentUser.baseDomainId]);

  const toggleRoleSelection = (roleId: string) => {
      const newSet = new Set(selectedRoleIds);
      if (newSet.has(roleId)) newSet.delete(roleId);
      else newSet.add(roleId);
      setSelectedRoleIds(newSet);
  };


  // --- Columns ---
  const columns = [
    { 
      header: '用户 / 组织', 
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                  <div 
                    className="flex items-center cursor-pointer select-none text-slate-200 hover:text-white group"
                    onClick={() => toggleDomain(row.data.id)}
                  >
                      <div className="mr-2 text-slate-500 transition-transform duration-200">
                          {row.expanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                      </div>
                      <Folder size={18} className="mr-2 text-yellow-500 fill-yellow-500/10" />
                      <span className="font-bold text-base mr-2">{row.data.name}</span>
                      <Badge color="gray" className="scale-90">{row.userCount} 用户</Badge>
                  </div>
              );
          } else {
              return (
                  <div className="flex items-center pl-10">
                       {/* Tree visual lines */}
                      <div className="absolute left-[29px] w-[1px] h-full bg-transparent border-l border-slate-700/50 -top-4 bottom-0"></div>
                      <div className="relative flex items-center">
                          <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center mr-3 border border-slate-600 text-slate-300">
                              <UserIcon size={16} />
                          </div>
                          <div>
                              <div className="text-slate-200 font-medium text-sm">{row.data.realName}</div>
                              <div className="text-slate-500 text-xs">{row.data.username}</div>
                          </div>
                      </div>
                  </div>
              );
          }
      },
      width: '30%'
    },
    { 
        header: '联系方式', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            return (
                <div className="flex flex-col text-xs text-slate-400 space-y-1">
                    <div className="flex items-center"><Phone size={12} className="mr-1 opacity-70"/> {row.data.phone}</div>
                    <div className="flex items-center"><Mail size={12} className="mr-1 opacity-70"/> {row.data.email}</div>
                </div>
            )
        }
    },
    { 
        header: '关联角色 (本域)', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            // Filter roles strictly for this domain context
            const roles = row.data.roles.filter(r => r.targetDomainId === row.data.baseDomainId);
            if (roles.length === 0) return <span className="text-slate-600 text-xs italic">未分配角色</span>;

            return (
                <div className="flex gap-1 flex-wrap">
                    {roles.map((r, i) => (
                        <Badge key={i} color="blue" className="flex items-center gap-1">
                            <Shield size={10} />
                            {MOCK_ROLES.find(role => role.id === r.roleId)?.name || r.roleName || '未知角色'}
                        </Badge>
                    ))}
                </div>
            )
        } 
    },
    { 
        header: '状态', 
        accessor: (row: TreeItem) => {
            if (row.type === 'domain') return null;
            return (
                <Switch 
                    checked={row.data.status === 'active'} 
                    onChange={(checked) => initiateStatusChange(row.data, checked)} 
                />
            )
        },
        width: '100px'
    },
    {
      header: '操作',
      accessor: (row: TreeItem) => {
          if (row.type === 'domain') {
              return (
                <Button size="sm" variant="ghost" className="text-blue-500 hover:bg-blue-500/10 hover:text-blue-400" icon={<Plus size={14} />} onClick={() => handleAdd(row.data.id)}>
                    新增用户
                </Button>
              )
          }
          return (
            <div className="flex space-x-2">
              <Button size="sm" variant="ghost" className="!text-blue-500 hover:!text-blue-400" icon={<Edit2 size={14} />} onClick={() => handleEdit(row.data)}>编辑</Button>
              <Button size="sm" variant="ghost" className="!text-red-500 hover:!text-red-400" icon={<Trash2 size={14} />} onClick={() => handleDelete(row.data.id)}>删除</Button>
            </div>
          )
      },
      width: '180px'
    }
  ];

  return (
    <div className="h-full flex flex-col space-y-4">
        {/* Header Actions */}
        <Card className="shrink-0">
            <div className="flex justify-between items-center">
                <div className="flex gap-4 items-center">
                    <Input 
                        placeholder="搜索姓名/账号/手机号..." 
                        className="w-64" 
                        value={searchKeyword} 
                        onChange={e => { setSearchKeyword(e.target.value); setCurrentPage(1); }}
                        prefix={<Search size={16}/>}
                    />
                    <Select 
                        className="w-40" 
                        options={[{label: '全部域', value: ''}, ...MOCK_DOMAINS.map(d => ({label: d.name, value: d.id}))]}
                        value={searchDomainId}
                        onChange={e => { setSearchDomainId(e.target.value); setCurrentPage(1); }}
                    />
                    <div className="flex gap-2">
                        <Button icon={<Search size={16} />}>查询</Button>
                        <Button variant="secondary" icon={<RotateCcw size={16} />} onClick={() => { setSearchKeyword(''); setSearchDomainId(''); setCurrentPage(1); }}>重置</Button>
                    </div>
                </div>
                {/* Global Add Button Removed to enforce adding via Domain Context */}
            </div>
        </Card>

        {/* Tree Table */}
        <Card className="flex-1 overflow-hidden flex flex-col" title="用户列表 (按域分组)">
            <div className="flex-1 overflow-auto">
                <Table columns={columns} data={paginatedData} keyField="id" />
            </div>
             <div className="py-2 border-t border-slate-700 flex justify-between items-center">
                <div className="text-sm text-slate-400">共 {flatTreeData.length} 条记录</div>
                <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
             </div>
        </Card>

        {/* Add/Edit Modal */}
        <Modal
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            title={currentUser.id ? "编辑用户" : "新增用户"}
            size="lg"
            footer={
                <>
                  <Button variant="secondary" onClick={() => setIsModalOpen(false)}>取消</Button>
                  <Button onClick={handleSave}>确定</Button>
                </>
              }
        >
            <div className="space-y-6">
                {/* 1. Basic Info */}
                <div>
                    <h4 className="text-sm font-bold text-slate-200 mb-3 border-l-2 border-blue-500 pl-2">基本信息</h4>
                    <div className="grid grid-cols-2 gap-4">
                        <Input 
                            label="用户名" 
                            placeholder="登录账号" 
                            value={currentUser.username || ''}
                            onChange={e => setCurrentUser({...currentUser, username: e.target.value})}
                        />
                        <Input 
                            label="真实姓名" 
                            placeholder="员工姓名" 
                            value={currentUser.realName || ''}
                            onChange={e => setCurrentUser({...currentUser, realName: e.target.value})}
                        />
                        <Input 
                            label="手机号" 
                            placeholder="11位手机号" 
                            value={currentUser.phone || ''}
                            onChange={e => setCurrentUser({...currentUser, phone: e.target.value})}
                        />
                        <Input 
                            label="邮箱" 
                            placeholder="Email" 
                            value={currentUser.email || ''}
                            onChange={e => setCurrentUser({...currentUser, email: e.target.value})}
                        />
                        <div className="col-span-2 relative">
                             <Select 
                                label="归属域 (部门/项目组)" 
                                options={MOCK_DOMAINS.map(d => ({ label: d.name, value: d.id }))}
                                value={currentUser.baseDomainId}
                                disabled={true}
                                className="opacity-60 cursor-not-allowed bg-slate-900/50"
                             />
                             <div className="absolute right-8 top-9 text-slate-500 pointer-events-none flex items-center gap-1">
                                <Lock size={12} />
                                <span className="text-xs">已锁定</span>
                             </div>
                             <p className="text-xs text-slate-500 mt-1">用户的归属域由创建时的上下文决定，不可变更。</p>
                        </div>
                         <div className="col-span-2">
                            <label className="text-sm font-medium text-slate-300 mb-1 block">账户状态</label>
                            <div className="flex items-center gap-3">
                                <span className="text-sm text-slate-400">正常</span>
                                <Switch 
                                    checked={currentUser.status === 'active'}
                                    onChange={c => setCurrentUser({...currentUser, status: c ? 'active' : 'locked'})}
                                />
                                <span className="text-sm text-slate-400">锁定</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* 2. Role Config */}
                <div>
                    <h4 className="text-sm font-bold text-slate-200 mb-3 border-l-2 border-green-500 pl-2 flex justify-between">
                        <span>角色分配</span>
                        <span className="text-xs font-normal text-slate-500 self-end">仅显示归属域 [{MOCK_DOMAINS.find(d => d.id === currentUser.baseDomainId)?.name}] 下的可用角色</span>
                    </h4>

                    <div className="bg-slate-900/50 rounded border border-slate-700 p-4 min-h-[100px]">
                        {availableRoles.length > 0 ? (
                            <div className="grid grid-cols-2 gap-3">
                                {availableRoles.map(role => (
                                    <label key={role.id} className="flex items-center p-2 rounded hover:bg-slate-800 cursor-pointer border border-transparent hover:border-slate-600 transition-colors">
                                        <input 
                                            type="checkbox" 
                                            className="rounded bg-slate-900 border-slate-600 text-blue-500 focus:ring-offset-slate-900 mr-3 h-4 w-4"
                                            checked={selectedRoleIds.has(role.id)}
                                            onChange={() => toggleRoleSelection(role.id)}
                                        />
                                        <div>
                                            <div className="text-sm text-slate-200 font-medium">{role.name}</div>
                                            <div className="text-xs text-slate-500">{role.code}</div>
                                        </div>
                                    </label>
                                ))}
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-500 py-4">
                                <Shield size={24} className="mb-2 opacity-50"/>
                                <span className="text-sm">该域下暂无可用角色，请先在角色管理中配置。</span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </Modal>

        <ConfirmDialog 
         isOpen={confirmOpen} 
         message={`确定要${targetStatusChange?.newStatus === 'active' ? '解锁' : '锁定'}该用户吗？`}
         onConfirm={confirmStatusChange}
         onCancel={() => { setConfirmOpen(false); setTargetStatusChange(null); }}
      />

      <ConfirmDialog 
         isOpen={deleteConfirmOpen} 
         title="删除用户"
         message="确定要删除该用户吗？此操作不可恢复。"
         onConfirm={confirmDelete}
         onCancel={() => { setDeleteConfirmOpen(false); setDeleteTargetId(null); }}
      />
    </div>
  );
};
